def _runtime_settings() -> Settings:
    return Settings()


def _control_plane_base_url(app_settings: Settings) -> str:
    lease = ControlPlaneLease(app_settings.data_dir / "control-plane.lock")
    try:
        raw = lease.metadata_path.read_text(encoding="utf-8").strip()
    except FileNotFoundError:
        raw = ""
    except OSError:
        raw = ""

    if raw:
        try:
            payload = json.loads(raw)
        except json.JSONDecodeError:
            payload = None
        if isinstance(payload, dict):
            host_value = str(payload.get("host") or "").strip()
            port_value = payload.get("port")
            if isinstance(port_value, bool):
                port_number = 0
            elif isinstance(port_value, int):
                port_number = port_value
            elif isinstance(port_value, str):
                try:
                    port_number = int(port_value)
                except ValueError:
                    port_number = 0
            else:
                port_number = 0
            if (
                host_value
                and port_number > 0
                and _control_plane_metadata_endpoint_is_reachable(host_value, port_number)
            ):
                return _watch_base_url(url=None, host=host_value, port=port_number)

    return _watch_base_url(url=None, host=app_settings.host, port=app_settings.port)


def _control_plane_metadata_endpoint_is_reachable(
    host: str,
    port: int,
    *,
    timeout_seconds: float = 0.35,
) -> bool:
    normalized_host = _normalize_local_control_plane_host(host)
    if normalized_host is None:
        return True
    try:
        with socket.create_connection((normalized_host, port), timeout=timeout_seconds):
            return True
    except OSError:
        return False


def _normalize_local_control_plane_host(host: str) -> str | None:
    value = str(host or "").strip().lower()
    if not value:
        return None
    if value in {"localhost", "127.0.0.1", "0.0.0.0"}:
        return "127.0.0.1"
    if value in {"::1", "[::1]", "::"}:
        return "::1"
    return None


def _try_live_api_model(
    base_url: str,
    path: str,
    model_type: Any,
    *,
    timeout_seconds: float,
) -> Any | None:
    try:
        payload = _watch_api_json(base_url, path, timeout_seconds=timeout_seconds)
    except RuntimeError:
        return None
    if not isinstance(payload, dict):
        return None
    try:
        return model_type.model_validate(payload)
    except Exception:
        return None


async def _try_live_dashboard_view(app_settings: Settings) -> DashboardView | None:
    base_url = _control_plane_base_url(app_settings)
    result = await asyncio.to_thread(
        _try_live_api_model,
        base_url,
        "/api/dashboard",
        DashboardView,
        timeout_seconds=20.0,
    )
    return cast("DashboardView | None", result)


async def _try_live_status_payload(app_settings: Settings) -> dict[str, object] | None:
    base_url = _control_plane_base_url(app_settings)
    try:
        payload = await asyncio.to_thread(
            _watch_api_json,
            base_url,
            "/api/status",
            timeout_seconds=8.0,
        )
    except RuntimeError:
        return None
    return payload if isinstance(payload, dict) else None


async def _build_live_health_payload(
    app_settings: Settings,
    *,
    timeout_ms: int,
) -> dict[str, object]:
    base_url = _control_plane_base_url(app_settings)
    timeout_seconds = timeout_ms / 1000
    health = await asyncio.to_thread(
        _watch_api_json,
        base_url,
        "/api/health",
        timeout_seconds=timeout_seconds,
    )
    if not isinstance(health, dict):
        raise RuntimeError("Gateway health response was not an object.")
    try:
        readiness = await asyncio.to_thread(
            _watch_api_json,
            base_url,
            "/readyz",
            timeout_seconds=timeout_seconds,
        )
    except RuntimeError as exc:
        readiness = {
            "ready": False,
            "failing": ["control-plane"],
            "error": str(exc),
        }
    if not isinstance(readiness, dict):
        readiness = {"ready": False, "failing": ["control-plane"]}
    status = _optional_cli_string(health.get("status")) or "unknown"
    control_plane = _optional_cli_string(health.get("controlPlane"))
    if control_plane is None:
        control_plane = _optional_cli_string(health.get("control_plane"))
    runtime_update = health.get("runtimeUpdate")
    if not isinstance(runtime_update, dict):
        runtime_update = health.get("runtime_update")
    return {
        "ok": status == "ok",
        "status": status,
        "controlPlane": control_plane,
        "ownerPid": health.get("ownerPid", health.get("owner_pid")),
        "lockPath": health.get("lockPath", health.get("lock_path")),
        "runtimeUpdate": dict(runtime_update) if isinstance(runtime_update, dict) else {},
        "readiness": dict(readiness),
    }


def _build_status_usage_unavailable_payload(*, timeout_ms: int) -> dict[str, object]:
    return {
        "status": "unavailable",
        "summary": (
            "Provider usage snapshots are not available from the native OpenZues CLI runtime yet."
        ),
        "reason": "Provider usage snapshots require the model provider usage runtime.",
        "timeoutMs": timeout_ms,
    }


def _build_status_security_audit_unavailable_payload() -> dict[str, object]:
    return {
        "status": "unavailable",
        "summary": (
            "Security audit snapshots are not available from the native OpenZues CLI runtime yet."
        ),
        "reason": "Security audit snapshots require the OpenZues runtime bridge audit adapter.",
        "findings": [],
    }


def _status_provider_usage_runtime(services: object | None) -> Any | None:
    if services is None:
        return None
    runtime = getattr(services, "provider_usage", None)
    if runtime is None:
        runtime = getattr(services, "provider_usage_service", None)
    return runtime


async def _build_status_usage_payload(
    services: object | None,
    *,
    timeout_ms: int,
) -> dict[str, object]:
    runtime = _status_provider_usage_runtime(services)
    for method_name in ("get_summary", "snapshot", "load_summary"):
        method = getattr(runtime, method_name, None) if runtime is not None else None
        if callable(method):
            result = await method(timeout_ms=timeout_ms)
            payload = dict(result) if isinstance(result, dict) else {}
            payload.setdefault("timeoutMs", timeout_ms)
            return payload
    return _build_status_usage_unavailable_payload(timeout_ms=timeout_ms)


def _status_security_audit_runtime(services: object | None) -> Any | None:
    if services is None:
        return None
    runtime = getattr(services, "security_audit", None)
    if runtime is None:
        runtime = getattr(services, "security_audit_service", None)
    return runtime


async def _build_status_security_audit_payload(
    services: object | None,
    *,
    timeout_ms: int,
) -> dict[str, object]:
    runtime = _status_security_audit_runtime(services)
    for method_name in ("get_audit", "snapshot", "run_audit"):
        method = getattr(runtime, method_name, None) if runtime is not None else None
        if callable(method):
            result = await method(timeout_ms=timeout_ms)
            return dict(result) if isinstance(result, dict) else {}
    return _build_status_security_audit_unavailable_payload()


def _build_status_gateway_service_payload() -> dict[str, object]:
    return {
        "label": "OpenZues gateway service",
        "installed": None,
        "loaded": False,
        "managedByOpenClaw": False,
        "externallyManaged": False,
        "loadedText": "native OpenZues app runtime; no OpenClaw-managed gateway service",
        "runtime": None,
        "runtimeShort": None,
    }


def _build_status_node_service_payload() -> dict[str, object]:
    return {
        "label": "OpenZues node service",
        "installed": None,
        "loaded": False,
        "managedByOpenClaw": False,
        "externallyManaged": False,
        "loadedText": "native OpenZues app runtime; no OpenClaw-managed node service",
        "runtime": None,
        "runtimeShort": None,
    }


async def _build_status_runtime_sections(
    app_settings: Settings,
    *,
    deep: bool,
    usage: bool,
    all_output: bool,
    timeout_ms: int,
    services: object | None = None,
) -> dict[str, object]:
    sections: dict[str, object] = {
        "gatewayService": _build_status_gateway_service_payload(),
        "nodeService": _build_status_node_service_payload(),
    }
    if deep:
        try:
            sections["health"] = await _build_live_health_payload(
                app_settings,
                timeout_ms=timeout_ms,
            )
        except RuntimeError as exc:
            sections["health"] = {
                "status": "unavailable",
                "summary": "Gateway health probe is unavailable.",
                "error": str(exc),
            }
    if deep or usage:
        sections["lastHeartbeat"] = None
    if usage:
        sections["usage"] = await _build_status_usage_payload(
            services,
            timeout_ms=timeout_ms,
        )
    if all_output:
        sections["securityAudit"] = await _build_status_security_audit_payload(
            services,
            timeout_ms=timeout_ms,
        )
    return sections


