@dataclass(slots=True)
class CliServices:
    settings: Settings
    database: Database
    manager: RuntimeManager
    control_chat: ControlChatService
    project_service: ProjectService
    mission_service: MissionService
    access: AccessService
    onboarding: OnboardingService
    gateway_capability: GatewayCapabilityService
    gateway_agents: GatewayAgentsService
    gateway_channels: GatewayChannelsService
    gateway_commands: GatewayCommandsService
    gateway_config: GatewayConfigService
    gateway_logs: GatewayLogsService
    model_scan: GatewayModelScanService
    gateway_node_methods: GatewayNodeMethodService
    ops_mesh: OpsMeshService
    recall: RecallService
    hermes_platform: HermesPlatformService
    gateway_bootstrap: GatewayBootstrapService
    runtime_updates: RuntimeUpdateService
    setup: SetupService
    plugin_clawhub_installer: CliClawHubPluginInstaller
    plugin_npm_installer: CliNpmPluginInstaller
    hook_npm_installer: CliNpmHookPackInstaller


async def _build_services(app_settings: Settings) -> CliServices:
    database = Database(app_settings.effective_db_path)
    hub = BroadcastHub()
    desktop_service = CodexDesktopService(
        approval_policy=app_settings.desktop_approval_policy,
        sandbox_mode=app_settings.desktop_sandbox_mode,
    )
    manager = RuntimeManager(database, hub, desktop_service=desktop_service)
    access = AccessService(database)
    environment = EnvironmentService(desktop_service=desktop_service)
    vault = VaultService(database, app_settings)
    launch_routing = LaunchRoutingService(database, manager)
    mission_service = MissionService(database, manager, hub)
    project_service = ProjectService(GitHubService())
    gateway_config = GatewayConfigService(
        assistant_name=app_settings.app_name,
        assistant_avatar="/static/favicon.svg",
        assistant_agent_id="openzues",
        server_version=__version__,
        local_media_preview_roots=[],
        embed_sandbox="scripts",
        allow_external_embed_urls=False,
        data_dir=app_settings.data_dir,
    )
    ops_mesh = OpsMeshService(
        database,
        manager,
        mission_service,
        hub,
        vault,
        playbooks=PlaybookService(),
        launch_routing=launch_routing,
        gateway_config_service=gateway_config,
    )
    gateway_bootstrap = GatewayBootstrapService(database, manager, access, launch_routing)
    gateway_agents = GatewayAgentsService(database=database)
    gateway_commands = GatewayCommandsService()
    gateway_node_pairing = GatewayNodePairingService(database)
    setup = SetupService(database, manager, access, gateway_bootstrap, ops_mesh)
    plugin_clawhub_installer = CliClawHubPluginInstaller(data_dir=app_settings.data_dir)
    plugin_npm_installer = CliNpmPluginInstaller(data_dir=app_settings.data_dir)
    hook_npm_installer = CliNpmHookPackInstaller(data_dir=app_settings.data_dir)
    onboarding = OnboardingService(
        database,
        manager,
        access,
        ops_mesh,
        gateway_bootstrap,
        setup,
    )
    remote_ops = RemoteOpsService(
        database,
        manager,
        mission_service,
        ops_mesh,
        hub,
    )
    gateway_capability = GatewayCapabilityService(
        database,
        manager,
        mission_service,
        access,
        remote_ops,
        ops_mesh,
        gateway_bootstrap,
        environment,
    )
    gateway_channels = GatewayChannelsService(
        list_notification_route_views=ops_mesh.list_notification_route_views,
        probe_account=ops_mesh.probe_channel_account,
        resolve_targets=ops_mesh.resolve_channel_targets,
    )
    gateway_logs = GatewayLogsService(logs_root=app_settings.data_dir.parent / "logs")
    model_scan = GatewayModelScanService()
    control_chat = ControlChatService(
        database,
        mission_service,
        manager,
        hub,
    )
    runtime_updates = RuntimeUpdateService(
        database,
        enabled=app_settings.auto_self_update_enabled,
        poll_interval_seconds=app_settings.auto_self_update_poll_interval_seconds,
        restart_callback=lambda: asyncio.sleep(0),
    )

    async def run_runtime_update(
        *,
        timeout_ms: int | None = None,
    ) -> dict[str, object]:
        return await runtime_updates.run_update(timeout_ms=timeout_ms)

    async def submit_gateway_chat_message(
        *,
        session_key: str,
        message: str,
        idempotency_key: str,
        thinking: str | None,
        deliver: bool | None,
        timeout_ms: int | None,
        channel: str | None = None,
        to: str | None = None,
        bootstrap_context_mode: str | None = None,
        bootstrap_context_run_kind: str | None = None,
    ) -> dict[str, object]:
        del (
            thinking,
            deliver,
            timeout_ms,
            channel,
            to,
            bootstrap_context_mode,
            bootstrap_context_run_kind,
        )
        dashboard_services = cast(
            CliServices,
            SimpleNamespace(
                settings=app_settings,
                database=database,
                manager=manager,
                control_chat=control_chat,
                project_service=project_service,
                mission_service=mission_service,
                access=access,
                onboarding=onboarding,
                gateway_capability=gateway_capability,
                gateway_agents=gateway_agents,
                gateway_channels=gateway_channels,
                gateway_commands=gateway_commands,
                gateway_node_methods=None,
                gateway_logs=gateway_logs,
                model_scan=model_scan,
                ops_mesh=ops_mesh,
                recall=None,
                hermes_platform=None,
                gateway_bootstrap=gateway_bootstrap,
                runtime_updates=runtime_updates,
                setup=setup,
            ),
        )
        dashboard = await _build_operator_dashboard(dashboard_services)
        await control_chat.submit(message, cast(DashboardView, dashboard), session_key=session_key)
        return {"runId": idempotency_key, "status": "ok"}

    gateway_node_methods = GatewayNodeMethodService(
        GatewayNodeRegistry(),
        database=database,
        hub=hub,
        agents_service=gateway_agents,
        pairing_service=gateway_node_pairing,
        channels_service=gateway_channels,
        commands_service=gateway_commands,
        config_service=gateway_config,
        list_notification_route_views=ops_mesh.list_notification_route_views,
        logs_service=gateway_logs,
        models_service=GatewayModelsService(list_instance_views=manager.list_views),
        send_channel_message_service=ops_mesh.send_direct_channel_message,
        send_channel_poll_service=ops_mesh.send_direct_channel_poll,
        message_action_dispatcher=ops_mesh.dispatch_message_action,
        acp_spawn_service=RuntimeManagerAcpSpawnService(
            manager,
            parent_stream_relay=FileAcpParentStreamRelay(app_settings.data_dir),
        ),
        sandbox_chat_send_service=RuntimeManagerSandboxChatSendService(manager),
        subagent_thread_binder=GatewaySubagentThreadBinderRegistry(
            list_notification_route_views=ops_mesh.list_notification_route_views,
            message_action_dispatcher=ops_mesh.dispatch_message_action,
        ),
        chat_send_service=submit_gateway_chat_message,
        runtime_update_runner=run_runtime_update,
    )
    ops_mesh.session_delivery_service = control_chat.append_session_assistant_message
    recall = RecallService(mission_service, database)
    hermes_platform = HermesPlatformService(
        database,
        manager,
        mission_service,
        project_service,
        gateway_bootstrap,
        app_settings,
        runtime_updates=runtime_updates,
        poll_interval_seconds=app_settings.hermes_learning_poll_interval_seconds,
    )

    app_settings.data_dir.mkdir(parents=True, exist_ok=True)
    vault.initialize()
    await database.initialize()
    await access.initialize()
    await manager.load(auto_connect=False)
    return CliServices(
        settings=app_settings,
        database=database,
        manager=manager,
        control_chat=control_chat,
        project_service=project_service,
        mission_service=mission_service,
        access=access,
        onboarding=onboarding,
        gateway_capability=gateway_capability,
        gateway_agents=gateway_agents,
        gateway_channels=gateway_channels,
        gateway_commands=gateway_commands,
        gateway_config=gateway_config,
        gateway_logs=gateway_logs,
        model_scan=model_scan,
        gateway_node_methods=gateway_node_methods,
        ops_mesh=ops_mesh,
        recall=recall,
        hermes_platform=hermes_platform,
        gateway_bootstrap=gateway_bootstrap,
        runtime_updates=runtime_updates,
        setup=setup,
        plugin_clawhub_installer=plugin_clawhub_installer,
        plugin_npm_installer=plugin_npm_installer,
        hook_npm_installer=hook_npm_installer,
    )


def _run(coro):
    return asyncio.run(coro)


async def _close_services(services: CliServices) -> None:
    await services.control_chat.close_attention_queue()
    await services.runtime_updates.close()
    await services.hermes_platform.close()
    await services.ops_mesh.close()
    await services.mission_service.close()
    await services.manager.close()


async def _run_with_services(action):
    services = await _build_services(_runtime_settings())
    try:
        return await action(services)
    finally:
        await _close_services(services)


def _emit_payload(payload: object, *, json_output: bool) -> None:
    if json_output:
        typer.echo(json.dumps(payload, indent=2))
        return
    if isinstance(payload, dict):
        headline = payload.get("headline")
        summary = payload.get("summary")
        if headline:
            typer.echo(str(headline))
        if summary:
            typer.echo(str(summary))
        warnings = payload.get("warnings")
        if isinstance(warnings, list):
            for warning in warnings:
                typer.echo(f"warning: {warning}")
        api_key = payload.get("api_key")
        if api_key:
            typer.echo(f"api_key: {api_key}")
        return
    typer.echo(str(payload))


def _emit_health(payload: dict[str, object], *, json_output: bool) -> None:
    if json_output:
        _emit_payload(payload, json_output=True)
        return
    status = str(payload.get("status") or "unknown")
    typer.echo(f"Gateway health: {status}")
    control_plane = str(payload.get("controlPlane") or "").strip()
    if control_plane:
        typer.echo(f"control plane: {control_plane}")
    readiness = payload.get("readiness")
    if isinstance(readiness, dict):
        ready = readiness.get("ready") is True
        typer.echo(f"readiness: {'ready' if ready else 'not ready'}")
        failing = readiness.get("failing")
        if isinstance(failing, list) and failing:
            typer.echo("failing: " + ", ".join(str(item) for item in failing))
    runtime_update = payload.get("runtimeUpdate")
    if isinstance(runtime_update, dict) and runtime_update:
        update_status = str(
            runtime_update.get("status")
            or runtime_update.get("state")
            or runtime_update.get("summary")
            or "available"
        )
        typer.echo(f"runtime update: {update_status}")


def _emit_agents_inventory(payload: dict[str, object], *, json_output: bool) -> None:
    if json_output:
        _emit_payload(payload, json_output=True)
        return

    agents = payload.get("agents")
    if not isinstance(agents, list):
        _emit_payload(payload, json_output=False)
        return

    default_id = str(payload.get("defaultId") or "").strip()
    main_key = str(payload.get("mainKey") or "").strip()
    scope = str(payload.get("scope") or "").strip()
    typer.echo("Agents:")
    summary_bits: list[str] = []
    if default_id:
        summary_bits.append(f"default: {default_id}")
    if main_key:
        summary_bits.append(f"main key: {main_key}")
    if scope:
        summary_bits.append(f"scope: {scope}")
    if summary_bits:
        typer.echo("  " + " | ".join(summary_bits))

    for agent in agents:
        if not isinstance(agent, dict):
            continue
        agent_id = str(agent.get("id") or "").strip()
        if not agent_id:
            continue
        label = str(agent.get("name") or "").strip()
        heading = f"- {agent_id}"
        if label and label != agent_id:
            heading += f" ({label})"
        if agent_id == default_id:
            heading += " [default]"
        typer.echo(heading)

        workspace = str(agent.get("workspace") or "").strip()
        if workspace:
            typer.echo("  workspace: " + workspace)

        identity = agent.get("identity")
        if isinstance(identity, dict):
            identity_name = str(identity.get("name") or "").strip()
            avatar_url = str(identity.get("avatarUrl") or identity.get("avatar") or "").strip()
            identity_bits = [bit for bit in (identity_name, avatar_url) if bit]
            if identity_bits:
                typer.echo("  identity: " + " | ".join(identity_bits))

        model = agent.get("model")
        if isinstance(model, dict):
            primary_model = str(model.get("primary") or "").strip()
            if primary_model:
                typer.echo("  model: " + primary_model)


def _emit_channel_inventory(payload: dict[str, object], *, json_output: bool) -> None:
    if json_output:
        _emit_payload(payload, json_output=True)
        return

    channel_order = payload.get("channelOrder")
    if not isinstance(channel_order, list):
        _emit_payload(payload, json_output=False)
        return

    channel_labels = payload.get("channelLabels")
    channel_detail_labels = payload.get("channelDetailLabels")
    channel_accounts = payload.get("channelAccounts")
    channel_default_account_id = payload.get("channelDefaultAccountId")
    channels = payload.get("channels")
    if not isinstance(channel_labels, dict):
        channel_labels = {}
    if not isinstance(channel_detail_labels, dict):
        channel_detail_labels = {}
    if not isinstance(channel_accounts, dict):
        channel_accounts = {}
    if not isinstance(channel_default_account_id, dict):
        channel_default_account_id = {}
    if not isinstance(channels, dict):
        channels = {}

    typer.echo("Channels:")
    route_count = payload.get("routeCount")
    enabled_count = payload.get("enabledCount")
    conversation_target_count = payload.get("conversationTargetCount")
    summary_bits: list[str] = []
    if isinstance(route_count, int):
        summary_bits.append(f"routes: {route_count}")
    if isinstance(enabled_count, int):
        summary_bits.append(f"enabled: {enabled_count}")
    if isinstance(conversation_target_count, int):
        summary_bits.append(f"targets: {conversation_target_count}")
    if summary_bits:
        typer.echo("  " + " | ".join(summary_bits))

    for channel_id_value in channel_order:
        channel_id = str(channel_id_value or "").strip()
        if not channel_id:
            continue
        label = str(channel_labels.get(channel_id) or channel_id).strip() or channel_id
        detail_label = str(channel_detail_labels.get(channel_id) or label).strip() or label
        heading = f"- {detail_label}"
        if channel_id != detail_label:
            heading += f" ({channel_id})"
        typer.echo(heading)

        summary = channels.get(channel_id)
        if isinstance(summary, dict):
            stats: list[str] = []
            for key, label_name in (
                ("routeCount", "routes"),
                ("enabledRouteCount", "enabled"),
                ("conversationTargetCount", "targets"),
                ("accountCount", "accounts"),
            ):
                value = summary.get(key)
                if isinstance(value, int):
                    stats.append(f"{value} {label_name}")
            if stats:
                typer.echo("  " + ", ".join(stats))

        default_account_id = str(channel_default_account_id.get(channel_id) or "").strip()
        if default_account_id:
            typer.echo("  default account: " + default_account_id)

        accounts = channel_accounts.get(channel_id)
        if isinstance(accounts, list):
            for account in accounts[:3]:
                if not isinstance(account, dict):
                    continue
                account_id = str(account.get("accountId") or "").strip()
                if not account_id:
                    continue
                bits: list[str] = []
                for key, label_name in (
                    ("routeCount", "routes"),
                    ("enabledRouteCount", "enabled"),
                    ("conversationTargetCount", "targets"),
                ):
                    value = account.get(key)
                    if isinstance(value, int):
                        bits.append(f"{value} {label_name}")
                line = f"  - {account_id}"
                if bits:
                    line += ": " + ", ".join(bits)
                typer.echo(line)


def _emit_channel_capabilities(payload: dict[str, object], *, json_output: bool) -> None:
    if json_output:
        _emit_payload(payload, json_output=True)
        return
    reports = payload.get("channels")
    if not isinstance(reports, list) or not reports:
        typer.echo("No channel capabilities found.")
        return
    for report in reports:
        if not isinstance(report, dict):
            continue
        channel = str(report.get("channel") or "channel").strip()
        account_id = str(report.get("accountId") or "default").strip()
        typer.echo(f"{channel}:{account_id}")
        support = report.get("support")
        if isinstance(support, dict):
            bits: list[str] = []
            chat_types = support.get("chatTypes")
            if isinstance(chat_types, list) and chat_types:
                bits.append("chatTypes=" + ",".join(str(item) for item in chat_types))
            for key in (
                "polls",
                "reactions",
                "edit",
                "unsend",
                "reply",
                "effects",
                "groupManagement",
                "threads",
                "media",
                "nativeCommands",
                "blockStreaming",
            ):
                if support.get(key) is True:
                    bits.append(key)
            typer.echo("  Support: " + (" ".join(bits) if bits else "none"))
        actions = report.get("actions")
        if isinstance(actions, list) and actions:
            typer.echo("  Actions: " + ", ".join(str(action) for action in actions))
        probe = report.get("probe")
        if isinstance(probe, dict):
            typer.echo("  Probe: " + str(probe.get("status") or "unknown"))


def _emit_channel_resolve_results(
    results: list[dict[str, object]],
    *,
    json_output: bool,
) -> None:
    if json_output:
        _emit_payload(results, json_output=True)
        return
    if not results:
        typer.echo("No channel targets resolved.")
        return
    for result in results:
        entry = str(result.get("input") or "").strip()
        if result.get("resolved") is True and result.get("id"):
            name = str(result.get("name") or "").strip()
            note = str(result.get("note") or "").strip()
            line = f"{entry} -> {result['id']}"
            if name:
                line += f" ({name})"
            if note:
                line += f" [{note}]"
            typer.echo(line)
            continue
        typer.echo(f"{entry} -> unresolved")


def _emit_channel_logs(payload: dict[str, object], *, json_output: bool) -> None:
    if json_output:
        _emit_payload(payload, json_output=True)
        return
    typer.echo(f"Log file: {payload.get('file') or ''}")
    channel = str(payload.get("channel") or "all").strip()
    if channel and channel != "all":
        typer.echo(f"Channel: {channel}")
    lines = payload.get("lines")
    if not isinstance(lines, list) or not lines:
        typer.echo("No matching log lines.")
        return
    for line in lines:
        if not isinstance(line, dict):
            continue
        parts = [
            str(line.get(key) or "").strip()
            for key in ("time", "level", "message")
            if str(line.get(key) or "").strip()
        ]
        typer.echo(" ".join(parts))


