    return {
        "ok": True,
        "status": "ready",
        "headline": f"Browser {label} captured",
        "summary": f"Captured {len(lines)} {label} line(s) from session {session}.",
        "session": session,
        "line_count": len(lines),
        "lines": lines,
    }


