def _sandbox_docker_available() -> bool:
    docker_command = shutil.which("docker")
    if docker_command is None:
        return False
    try:
        result = subprocess.run(
            [docker_command, "version", "--format", "{{.Server.Version}}"],
            capture_output=True,
            check=False,
            text=True,
            timeout=5,
        )
    except (OSError, subprocess.SubprocessError):
        return False
    return result.returncode == 0


def _doctor_sandbox_docker_unavailable_warning(mode: str) -> str:
    return "\n".join(
        [
            f'Sandbox mode is enabled (mode: "{mode}") but Docker is not available.',
            "Docker is required for sandbox mode to function.",
            "Isolated sessions (cron jobs, sub-agents) will fail without Docker.",
            "",
            "Options:",
            "- Install Docker and restart the gateway",
            "- Disable sandbox mode: openclaw config set agents.defaults.sandbox.mode off",
        ]
    )


def _doctor_sandbox_warning_from_config(
    config_service: GatewayConfigService | None,
) -> str | None:
    if config_service is None:
        return None
    try:
        snapshot = config_service.build_snapshot()
    except Exception:
        return None
    sandbox_config = _doctor_sandbox_config_from_snapshot(snapshot)
    if sandbox_config is None:
        return None
    mode = _doctor_sandbox_mode(sandbox_config.get("mode"))
    if mode == "off":
        return None
    backend = _doctor_sandbox_backend(sandbox_config.get("backend"))
    if backend != "docker":
        return None
    if _sandbox_docker_available():
        return None
    return _doctor_sandbox_docker_unavailable_warning(mode)


def _doctor_sandbox_scope_warnings_from_config(
    config_service: GatewayConfigService | None,
) -> list[str]:
    if config_service is None:
        return []
    try:
        snapshot = config_service.build_snapshot()
    except Exception:
        return []
    return _doctor_sandbox_scope_warnings_from_snapshot(snapshot)


def _build_doctor_legacy_config_payload(
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    base_payload: dict[str, object] = {
        "source": "openzues-native",
        "openClawContribution": "doctor:legacy-config",
        "repairRequested": should_repair,
        "repairAvailable": False,
        "issues": [],
        "warnings": [],
    }
    if config_service is None:
        return {
            **base_payload,
            "status": "unavailable",
            "summary": "Gateway config is unavailable for legacy config checks.",
        }
    if should_repair:
        repair = getattr(config_service, "repair_legacy_config", None)
        if not callable(repair):
            repair = getattr(config_service, "repair_legacy_thread_binding_ttl_hours", None)
        if not callable(repair):
            return {
                **base_payload,
                "status": "unavailable",
                "summary": "Legacy config repair runtime is unavailable.",
            }
        try:
            result = repair()
        except Exception as exc:
            return {
                **base_payload,
                "status": "error",
                "summary": f"Legacy config repair failed: {exc}",
            }
        result_payload = dict(result) if isinstance(result, dict) else {"result": result}
        changes = _object_list(result_payload.get("changes"))
        changed = result_payload.get("changed") is True
        summary = (
            "Migrated legacy config."
            if changed
            else "No legacy config keys found."
        )
        return {
            **base_payload,
            "status": "ok",
            "summary": summary,
            "repairAvailable": True,
            "changed": changed,
            "changes": changes,
            "path": result_payload.get("path"),
        }

    detect = getattr(config_service, "detect_legacy_config_issues", None)
    if not callable(detect):
        detect = getattr(config_service, "detect_legacy_thread_binding_ttl_hours", None)
    if not callable(detect):
        return {
            **base_payload,
            "status": "unavailable",
            "summary": "Legacy config detection runtime is unavailable.",
        }
    try:
        result = detect()
    except Exception as exc:
        return {
            **base_payload,
            "status": "error",
            "summary": f"Legacy config detection failed: {exc}",
        }
    result_payload = dict(result) if isinstance(result, dict) else {"result": result}
    issues = _object_list(result_payload.get("issues"))
    warning = _doctor_legacy_config_warning(issues)
    return {
        **base_payload,
        "status": "warn" if issues else "ok",
        "summary": _doctor_legacy_config_summary(issues),
        "repairAvailable": True,
        "issues": issues,
        "warnings": [warning] if warning else [],
        "path": result_payload.get("path"),
    }


def _with_doctor_legacy_config_payload(
    payload: dict[str, object],
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    legacy_payload = _build_doctor_legacy_config_payload(
        config_service,
        should_repair=should_repair,
    )
    next_payload = dict(payload)
    next_payload["legacyConfig"] = legacy_payload
    warnings = _object_list(legacy_payload.get("warnings"))
    if warnings:
        next_payload = _with_doctor_added_warnings(next_payload, [str(item) for item in warnings])
    return next_payload


def _config_service_path_label(config_service: object | None) -> str | None:
    config_path = getattr(config_service, "_config_path", None)
    return str(config_path) if isinstance(config_path, Path) else None


def _bundled_lookup_path(path_text: str) -> Path:
    expanded = os.path.expandvars(os.path.expanduser(path_text))
    try:
        return Path(expanded).resolve(strict=False)
    except OSError:
        return Path(expanded)


def _normalize_bundled_lookup_path(path_text: str) -> str:
    return str(_bundled_lookup_path(path_text)).rstrip("\\/")


def _bundled_plugin_load_path_hit(
    raw_path: str,
    *,
    plugins_config: dict[str, object],
    config_snapshot: dict[str, object],
) -> dict[str, object] | None:
    resolved = _bundled_lookup_path(raw_path)
    parts = resolved.parts
    for index, part in enumerate(parts):
        if part.lower() != "extensions" or index == 0 or index >= len(parts) - 1:
            continue
        previous = parts[index - 1].lower()
        if previous in {"dist", "dist-runtime"}:
            continue
        package_root = Path(*parts[:index])
        bundled_leaf = Path(*parts[index + 1 :])
        for bundled_root in ("dist", "dist-runtime"):
            candidate = package_root / bundled_root / "extensions" / bundled_leaf
            manifest_path = _plugin_manifest_path_for_load_path(candidate)
            if manifest_path is None:
                continue
            record = _plugin_record_from_openclaw_manifest(
                manifest_path,
                plugins_config=plugins_config,
                config_snapshot=config_snapshot,
            )
            if record is None:
                continue
            plugin_id = _optional_cli_string(record.get("id")) or bundled_leaf.name
            return {
                "pluginId": plugin_id,
                "fromPath": raw_path,
                "toPath": str(candidate),
                "pathLabel": "plugins.load.paths",
            }
    return None


def _scan_bundled_plugin_load_path_migrations(
    snapshot: dict[str, object],
) -> list[dict[str, object]]:
    plugins = snapshot.get("plugins")
    plugins_config = dict(plugins) if isinstance(plugins, dict) else {}
    load = plugins_config.get("load")
    load_config = load if isinstance(load, dict) else {}
    raw_paths = load_config.get("paths")
    paths = raw_paths if isinstance(raw_paths, list) else []
    hits: list[dict[str, object]] = []
    seen: set[str] = set()
    for raw_path in paths:
        if not isinstance(raw_path, str):
            continue
        hit = _bundled_plugin_load_path_hit(
            raw_path,
            plugins_config=plugins_config,
            config_snapshot=snapshot,
        )
        if hit is None:
            continue
        dedupe_key = _normalize_bundled_lookup_path(str(hit.get("fromPath") or ""))
        if dedupe_key in seen:
            continue
        seen.add(dedupe_key)
        hits.append(hit)
    return hits


def _doctor_bundled_plugin_load_path_warnings(issues: Sequence[object]) -> list[str]:
    if not issues:
        return []
    warnings: list[str] = []
    for issue in issues:
        if not isinstance(issue, dict):
            continue
        path_label = str(issue.get("pathLabel") or "").strip()
        plugin_id = str(issue.get("pluginId") or "").strip()
        from_path = str(issue.get("fromPath") or "").strip()
        to_path = str(issue.get("toPath") or "").strip()
        if not path_label or not plugin_id or not from_path or not to_path:
            continue
        warnings.append(
            f'- {path_label}: legacy bundled plugin path "{from_path}" '
            f'still points at {plugin_id}; current packaged path is "{to_path}".'
        )
    if warnings:
        warnings.append(
            '- Run "openzues doctor --fix" to rewrite these bundled plugin paths.'
        )
    return warnings


def _build_doctor_bundled_plugin_load_paths_payload(
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    base_payload: dict[str, object] = {
        "source": "openzues-native",
        "openClawContribution": "doctor:bundled-plugin-load-paths",
        "repairRequested": should_repair,
        "repairAvailable": False,
        "issues": [],
        "warnings": [],
    }
    build_snapshot = getattr(config_service, "build_snapshot", None)
    if not callable(build_snapshot):
        return {
            **base_payload,
            "status": "unavailable",
            "summary": "Gateway config is unavailable for bundled plugin load path checks.",
        }
    try:
        raw_snapshot = build_snapshot()
    except Exception as exc:
        return {
            **base_payload,
            "status": "error",
            "summary": f"Bundled plugin load path detection failed: {exc}",
        }
    snapshot = raw_snapshot if isinstance(raw_snapshot, dict) else {}
    issues = _scan_bundled_plugin_load_path_migrations(snapshot)
    if should_repair:
        repair = getattr(config_service, "repair_bundled_plugin_load_paths", None)
        if not callable(repair):
            return {
                **base_payload,
                "status": "unavailable",
                "summary": "Bundled plugin load path repair runtime is unavailable.",
                "issues": issues,
                "warnings": _doctor_bundled_plugin_load_path_warnings(issues),
                "path": _config_service_path_label(config_service),
            }
        try:
            result = repair(issues)
        except Exception as exc:
            return {
                **base_payload,
                "status": "error",
                "summary": f"Bundled plugin load path repair failed: {exc}",
                "issues": issues,
                "warnings": _doctor_bundled_plugin_load_path_warnings(issues),
                "path": _config_service_path_label(config_service),
            }
        result_payload = dict(result) if isinstance(result, dict) else {"result": result}
        changed = result_payload.get("changed") is True
        remaining_issues = [] if changed else issues
        return {
            **base_payload,
            "status": "warn" if remaining_issues else "ok",
            "summary": (
                "Rewrote legacy bundled plugin load paths."
                if changed
                else (
                    "Legacy bundled plugin load paths found."
                    if remaining_issues
                    else "No legacy bundled plugin load paths found."
                )
            ),
            "repairAvailable": True,
            "changed": changed,
            "changes": _object_list(result_payload.get("changes")),
            "issues": remaining_issues,
            "warnings": _doctor_bundled_plugin_load_path_warnings(remaining_issues),
            "path": result_payload.get("path") or _config_service_path_label(config_service),
        }

    warnings = _doctor_bundled_plugin_load_path_warnings(issues)
    return {
        **base_payload,
        "status": "warn" if issues else "ok",
        "summary": (
            "Legacy bundled plugin load paths found."
            if issues
            else "No legacy bundled plugin load paths found."
        ),
        "repairAvailable": True,
        "issues": issues,
        "warnings": warnings,
        "path": _config_service_path_label(config_service),
    }


def _with_doctor_bundled_plugin_load_paths_payload(
    payload: dict[str, object],
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    load_paths_payload = _build_doctor_bundled_plugin_load_paths_payload(
        config_service,
        should_repair=should_repair,
    )
    next_payload = dict(payload)
    next_payload["bundledPluginLoadPaths"] = load_paths_payload
    warnings = _object_list(load_paths_payload.get("warnings"))
    if warnings:
        next_payload = _with_doctor_added_warnings(next_payload, [str(item) for item in warnings])
    return next_payload


_LEGACY_PLUGIN_MANIFEST_CONTRACT_KEYS = (
    "speechProviders",
    "mediaUnderstandingProviders",
    "imageGenerationProviders",
)


def _legacy_plugin_manifest_contract_migration(
    manifest_path: Path,
    raw: dict[str, object],
) -> dict[str, object] | None:
    next_raw: dict[str, object] = dict(raw)
    raw_contracts = raw.get("contracts")
    next_contracts: dict[str, object] = (
        dict(raw_contracts) if isinstance(raw_contracts, dict) else {}
    )
    change_lines: list[str] = []
    manifest_label = str(manifest_path)
    for key in _LEGACY_PLUGIN_MANIFEST_CONTRACT_KEYS:
        if key not in raw:
            continue
        legacy_values = _plugin_manifest_string_list(raw.get(key))
        contract_values = _plugin_manifest_string_list(next_contracts.get(key))
        if legacy_values and not contract_values:
            next_contracts[key] = legacy_values
            change_lines.append(
                f"- {manifest_label}: moved {key} to contracts.{key}"
            )
        else:
            change_lines.append(
                f"- {manifest_label}: removed legacy {key} (kept contracts.{key})"
            )
        next_raw.pop(key, None)
    if not change_lines:
        return None
    if next_contracts:
        next_raw["contracts"] = next_contracts
    else:
        next_raw.pop("contracts", None)
    return {
        "manifestPath": str(manifest_path),
        "pluginId": _optional_cli_string(raw.get("id")) or str(manifest_path),
        "nextRaw": next_raw,
        "changeLines": change_lines,
    }


def _collect_legacy_plugin_manifest_contract_migrations(
    snapshot: dict[str, object],
) -> list[dict[str, object]]:
    plugins = snapshot.get("plugins")
    plugins_config = dict(plugins) if isinstance(plugins, dict) else {}
    migrations: list[dict[str, object]] = []
    seen: set[str] = set()
    for load_path in _plugin_manifest_load_paths(plugins_config):
        manifest_path = _plugin_manifest_path_for_load_path(load_path)
        if manifest_path is None:
            continue
        manifest_key = str(manifest_path.resolve(strict=False))
        if manifest_key in seen:
            continue
        seen.add(manifest_key)
        raw = _read_cli_json_object(manifest_path)
        if raw is None:
            continue
        migration = _legacy_plugin_manifest_contract_migration(manifest_path, raw)
        if migration is not None:
            migrations.append(migration)
    return sorted(migrations, key=lambda item: str(item.get("manifestPath") or ""))


def _doctor_legacy_plugin_manifest_warnings(
    migrations: Sequence[object],
) -> list[str]:
    if not migrations:
        return []
    warnings = ["Legacy plugin manifest capability keys detected."]
    for migration in migrations:
        if not isinstance(migration, dict):
            continue
        for line in _object_list(migration.get("changeLines")):
            text = str(line).strip()
            if text:
                warnings.append(text)
    return warnings


def _apply_legacy_plugin_manifest_contract_migrations(
    migrations: Sequence[dict[str, object]],
) -> tuple[list[str], list[dict[str, object]]]:
    changes: list[str] = []
    errors: list[dict[str, object]] = []
    for migration in migrations:
        manifest_path_text = _optional_cli_string(migration.get("manifestPath"))
        next_raw = migration.get("nextRaw")
        if manifest_path_text is None or not isinstance(next_raw, dict):
            continue
        try:
            Path(manifest_path_text).write_text(
                f"{json.dumps(next_raw, indent=2)}\n",
                encoding="utf-8",
            )
        except OSError as exc:
            errors.append(
                {
                    "manifestPath": manifest_path_text,
                    "message": f"Failed to rewrite legacy plugin manifest: {exc}",
                }
            )
            continue
        changes.extend(str(line) for line in _object_list(migration.get("changeLines")))
    return changes, errors


def _build_doctor_legacy_plugin_manifests_payload(
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    base_payload: dict[str, object] = {
        "source": "openzues-native",
        "openClawContribution": "doctor:legacy-plugin-manifests",
        "repairRequested": should_repair,
        "repairAvailable": True,
        "migrations": [],
        "warnings": [],
    }
    build_snapshot = getattr(config_service, "build_snapshot", None)
    if not callable(build_snapshot):
        return {
            **base_payload,
            "status": "unavailable",
            "summary": "Gateway config is unavailable for plugin manifest checks.",
            "repairAvailable": False,
        }
    try:
        raw_snapshot = build_snapshot()
    except Exception as exc:
        return {
            **base_payload,
            "status": "error",
            "summary": f"Plugin manifest migration detection failed: {exc}",
        }
    snapshot = raw_snapshot if isinstance(raw_snapshot, dict) else {}
    migrations = _collect_legacy_plugin_manifest_contract_migrations(snapshot)
    if should_repair:
        changes, errors = _apply_legacy_plugin_manifest_contract_migrations(migrations)
        remaining_migrations = migrations if errors else []
        warnings = _doctor_legacy_plugin_manifest_warnings(remaining_migrations)
        status = "error" if errors else ("ok" if changes or not migrations else "warn")
        return {
            **base_payload,
            "status": status,
            "summary": (
                "Rewrote legacy plugin manifest capability keys into contracts."
                if changes and not errors
                else (
                    "Legacy plugin manifest repair had errors."
                    if errors
                    else "No legacy plugin manifest capability keys found."
                )
            ),
            "changed": bool(changes) and not errors,
            "changes": changes,
            "errors": errors,
            "migrations": remaining_migrations,
            "warnings": warnings,
        }
    warnings = _doctor_legacy_plugin_manifest_warnings(migrations)
    return {
        **base_payload,
        "status": "warn" if migrations else "ok",
        "summary": (
            "Legacy plugin manifest capability keys found."
            if migrations
            else "No legacy plugin manifest capability keys found."
        ),
        "migrations": migrations,
        "warnings": warnings,
    }


def _with_doctor_legacy_plugin_manifests_payload(
    payload: dict[str, object],
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    manifest_payload = _build_doctor_legacy_plugin_manifests_payload(
        config_service,
        should_repair=should_repair,
    )
    next_payload = dict(payload)
    next_payload["legacyPluginManifests"] = manifest_payload
    warnings = _object_list(manifest_payload.get("warnings"))
    if warnings:
        next_payload = _with_doctor_added_warnings(next_payload, [str(item) for item in warnings])
    return next_payload


def _stale_plugin_registry_state(
    config_service: object | None,
) -> tuple[set[str], list[dict[str, object]]]:
    known_ids = set(_OPENZUES_NATIVE_PLUGIN_IDS)
    build_snapshot = getattr(config_service, "build_snapshot", None)
    if not callable(build_snapshot):
        return known_ids, []
    try:
        raw_snapshot = build_snapshot()
    except Exception as exc:
        return known_ids, [
            {
                "level": "error",
                "category": "pluginDiscovery",
                "code": "plugin_manifest_registry_unavailable",
                "message": f"Plugin manifest registry could not be read: {exc}",
            }
        ]
    snapshot = raw_snapshot if isinstance(raw_snapshot, dict) else {}
    plugins = snapshot.get("plugins")
    plugins_config = dict(plugins) if isinstance(plugins, dict) else {}
    diagnostics: list[dict[str, object]] = []
    for load_path in _plugin_manifest_load_paths(plugins_config):
        manifest_path = _plugin_manifest_path_for_load_path(load_path)
        if manifest_path is None:
            diagnostics.append(
                {
                    "level": "error",
                    "category": "pluginDiscovery",
                    "code": "plugin_manifest_missing",
                    "message": f"Plugin manifest not found for load path: {load_path}",
                    "source": str(load_path),
                }
            )
            continue
        record = _plugin_record_from_openclaw_manifest(
            manifest_path,
            plugins_config=plugins_config,
            config_snapshot=snapshot,
        )
        if record is None:
            diagnostics.append(
                {
                    "level": "error",
                    "category": "pluginDiscovery",
                    "code": "plugin_manifest_invalid",
                    "message": f"Plugin manifest could not be loaded: {manifest_path}",
                    "source": str(manifest_path),
                }
            )
            continue
        plugin_id = _optional_cli_string(record.get("id"))
        if plugin_id is not None:
            known_ids.add(plugin_id)
    return known_ids, diagnostics


def _doctor_stale_plugin_config_warnings(
    issues: list[object],
    *,
    auto_repair_blocked: bool,
) -> list[str]:
    if not issues:
        return []
    warnings: list[str] = []
    for issue in issues:
        if not isinstance(issue, dict):
            continue
        path_label = str(issue.get("pathLabel") or "").strip()
        plugin_id = str(issue.get("pluginId") or "").strip()
        if not path_label or not plugin_id:
            continue
        warnings.append(f'- {path_label}: stale plugin reference "{plugin_id}" was found.')
    if not warnings:
        return []
    if auto_repair_blocked:
        warnings.append(
            '- Auto-removal is paused because plugin discovery currently has errors. '
            'Fix plugin discovery first, then rerun "openzues doctor --fix".'
        )
    else:
        warnings.append(
            '- Run "openzues doctor --fix" to remove stale plugins.allow and '
            "plugins.entries ids."
        )
    return warnings


def _build_doctor_stale_plugin_config_payload(
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    base_payload: dict[str, object] = {
        "source": "openzues-native",
        "openClawContribution": "doctor:stale-plugin-config",
        "repairRequested": should_repair,
        "repairAvailable": False,
        "autoRepairBlocked": False,
        "issues": [],
        "warnings": [],
    }
    if config_service is None:
        return {
            **base_payload,
            "status": "unavailable",
            "summary": "Gateway config is unavailable for stale plugin config checks.",
        }
    known_plugin_ids, diagnostics = _stale_plugin_registry_state(config_service)
    auto_repair_blocked = any(
        isinstance(diagnostic, dict)
        and str(diagnostic.get("level") or "").strip() == "error"
        for diagnostic in diagnostics
    )
    if should_repair:
        repair = getattr(config_service, "repair_stale_plugin_config", None)
        if not callable(repair):
            return {
                **base_payload,
                "status": "unavailable",
                "summary": "Stale plugin config repair runtime is unavailable.",
                "autoRepairBlocked": auto_repair_blocked,
            }
        try:
            result = repair(
                known_plugin_ids,
                auto_repair_blocked=auto_repair_blocked,
            )
        except Exception as exc:
            return {
                **base_payload,
                "status": "error",
                "summary": f"Stale plugin config repair failed: {exc}",
                "autoRepairBlocked": auto_repair_blocked,
            }
        result_payload = dict(result) if isinstance(result, dict) else {"result": result}
        changed = result_payload.get("changed") is True
        changes = _object_list(result_payload.get("changes"))
        issues = [] if changed else _object_list(result_payload.get("issues"))
        warnings = _doctor_stale_plugin_config_warnings(
            issues,
            auto_repair_blocked=auto_repair_blocked,
        )
        payload = {
            **base_payload,
            "status": "warn" if issues else "ok",
            "summary": (
                "Removed stale plugin config references."
                if changed
                else (
                    "Stale plugin config references found."
                    if issues
                    else "No stale plugin config references found."
                )
            ),
            "repairAvailable": True,
            "autoRepairBlocked": auto_repair_blocked,
            "changed": changed,
            "changes": changes,
            "issues": issues,
            "warnings": warnings,
            "path": result_payload.get("path"),
        }
        if diagnostics:
            payload["diagnostics"] = diagnostics
        return payload

    detect = getattr(config_service, "detect_stale_plugin_config", None)
    if not callable(detect):
        return {
            **base_payload,
            "status": "unavailable",
            "summary": "Stale plugin config detection runtime is unavailable.",
            "autoRepairBlocked": auto_repair_blocked,
        }
    try:
        result = detect(
            known_plugin_ids,
            auto_repair_blocked=auto_repair_blocked,
        )
    except Exception as exc:
        return {
            **base_payload,
            "status": "error",
            "summary": f"Stale plugin config detection failed: {exc}",
            "autoRepairBlocked": auto_repair_blocked,
        }
    result_payload = dict(result) if isinstance(result, dict) else {"result": result}
    issues = _object_list(result_payload.get("issues"))
    warnings = _doctor_stale_plugin_config_warnings(
        issues,
        auto_repair_blocked=auto_repair_blocked,
    )
    payload = {
        **base_payload,
        "status": "warn" if issues else "ok",
        "summary": (
            "Stale plugin config references found."
            if issues
            else "No stale plugin config references found."
        ),
        "repairAvailable": True,
        "autoRepairBlocked": auto_repair_blocked,
        "issues": issues,
        "warnings": warnings,
        "path": result_payload.get("path"),
    }
    if diagnostics:
        payload["diagnostics"] = diagnostics
    return payload


def _with_doctor_stale_plugin_config_payload(
    payload: dict[str, object],
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    stale_payload = _build_doctor_stale_plugin_config_payload(
        config_service,
        should_repair=should_repair,
    )
    next_payload = dict(payload)
    next_payload["stalePluginConfig"] = stale_payload
    warnings = _object_list(stale_payload.get("warnings"))
    if warnings:
        next_payload = _with_doctor_added_warnings(next_payload, [str(item) for item in warnings])
    return next_payload


def _doctor_open_policy_allow_from_warnings(changes: Sequence[object]) -> list[str]:
    if not changes:
        return []
    warnings = [str(change) for change in changes if str(change).strip()]
    if warnings:
        warnings.append(
            '- Run "openzues doctor --fix" to add missing allowFrom wildcards.'
        )
    return warnings


def _build_doctor_open_policy_allow_from_payload(
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    base_payload: dict[str, object] = {
        "source": "openzues-native",
        "openClawContribution": "doctor:open-policy-allowfrom",
        "repairRequested": should_repair,
        "repairAvailable": False,
        "changes": [],
        "warnings": [],
    }
    if config_service is None:
        return {
            **base_payload,
            "status": "unavailable",
            "summary": "Gateway config is unavailable for open-policy allowFrom checks.",
        }
    if should_repair:
        repair = getattr(config_service, "repair_open_policy_allow_from", None)
        if not callable(repair):
            return {
                **base_payload,
                "status": "unavailable",
                "summary": "Open-policy allowFrom repair runtime is unavailable.",
            }
        try:
            result = repair()
        except Exception as exc:
            return {
                **base_payload,
                "status": "error",
                "summary": f"Open-policy allowFrom repair failed: {exc}",
            }
        result_payload = dict(result) if isinstance(result, dict) else {"result": result}
        changed = result_payload.get("changed") is True
        changes = _object_list(result_payload.get("changes"))
        return {
            **base_payload,
            "status": "ok",
            "summary": (
                "Repaired open DM allowFrom wildcards."
                if changed
                else "No open DM allowFrom wildcard repairs needed."
            ),
            "repairAvailable": True,
            "changed": changed,
            "changes": changes,
            "warnings": [],
            "path": result_payload.get("path") or _config_service_path_label(config_service),
        }

    detect = getattr(config_service, "detect_open_policy_allow_from", None)
    if not callable(detect):
        return {
            **base_payload,
            "status": "unavailable",
            "summary": "Open-policy allowFrom detection runtime is unavailable.",
        }
    try:
        result = detect()
    except Exception as exc:
        return {
            **base_payload,
            "status": "error",
            "summary": f"Open-policy allowFrom detection failed: {exc}",
        }
    result_payload = dict(result) if isinstance(result, dict) else {"result": result}
    changes = _object_list(result_payload.get("changes"))
    warnings = _doctor_open_policy_allow_from_warnings(changes)
    return {
        **base_payload,
        "status": "warn" if changes else "ok",
        "summary": (
            "Open DM policies are missing allowFrom wildcards."
            if changes
            else "Open DM allowFrom wildcard policy is current."
        ),
        "repairAvailable": True,
        "changes": changes,
        "warnings": warnings,
        "path": result_payload.get("path") or _config_service_path_label(config_service),
    }


def _with_doctor_open_policy_allow_from_payload(
    payload: dict[str, object],
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    allow_from_payload = _build_doctor_open_policy_allow_from_payload(
        config_service,
        should_repair=should_repair,
    )
    next_payload = dict(payload)
    next_payload["openPolicyAllowFrom"] = allow_from_payload
    warnings = _object_list(allow_from_payload.get("warnings"))
    if warnings:
        next_payload = _with_doctor_added_warnings(next_payload, [str(item) for item in warnings])
    return next_payload


def _doctor_allowlist_policy_allow_from_warnings(changes: Sequence[object]) -> list[str]:
    if not changes:
        return []
    warnings = [str(change) for change in changes if str(change).strip()]
    if warnings:
        warnings.append(
            '- Run "openzues doctor --fix" to restore missing allowFrom lists.'
        )
    return warnings


