def _doctor_sandbox_scope_warnings_from_snapshot(snapshot: dict[str, Any]) -> list[str]:
    warnings: list[str] = []
    for agents_config in _doctor_agents_config_roots(snapshot):
        defaults_config = agents_config.get("defaults")
        default_sandbox = (
            defaults_config.get("sandbox")
            if isinstance(defaults_config, dict)
            else None
        )
        default_scope = (
            default_sandbox.get("scope")
            if isinstance(default_sandbox, dict)
            else None
        )
        raw_agents = agents_config.get("list")
        if not isinstance(raw_agents, list):
            continue
        for raw_agent in raw_agents:
            if not isinstance(raw_agent, dict):
                continue
            agent_sandbox = raw_agent.get("sandbox")
            if not isinstance(agent_sandbox, dict):
                continue
            scope = _doctor_sandbox_scope(
                agent_sandbox.get("scope") or default_scope,
                per_session=agent_sandbox.get("perSession"),
            )
            if scope != "shared":
                continue
            overrides = [
                key
                for key in ("docker", "browser", "prune")
                if isinstance(agent_sandbox.get(key), dict) and agent_sandbox.get(key)
            ]
            if not overrides:
                continue
            agent_id = str(raw_agent.get("id") or "").strip()
            warnings.append(
                "\n".join(
                    [
                        f'- agents.list (id "{agent_id}") sandbox '
                        f'{"/".join(overrides)} overrides ignored.',
                        '  scope resolves to "shared".',
                    ]
                )
            )
    return warnings


def _with_doctor_sandbox_warnings(
    payload: dict[str, object],
    config_service: GatewayConfigService | None,
) -> dict[str, object]:
    warnings_to_add = [
        warning
        for warning in (
            _doctor_sandbox_warning_from_config(config_service),
            *_doctor_sandbox_scope_warnings_from_config(config_service),
        )
        if warning
    ]
    if not warnings_to_add:
        return payload
    next_payload = dict(payload)
    existing = next_payload.get("warnings")
    if isinstance(existing, list):
        warnings = list(existing)
    elif existing is None:
        warnings = []
    else:
        warnings = [existing]
    existing_warnings = {str(item) for item in warnings}
    for warning in warnings_to_add:
        if warning in existing_warnings:
            continue
        warnings.append(warning)
        existing_warnings.add(warning)
    next_payload["warnings"] = warnings
    return next_payload


def _build_doctor_sandbox_payload(config_service: object | None) -> dict[str, object]:
    build_snapshot = getattr(config_service, "build_snapshot", None)
    if not callable(build_snapshot):
        return {
            "status": "unavailable",
            "summary": "Gateway config is unavailable for sandbox doctor checks.",
            "source": "openzues-native",
            "openClawContribution": "doctor:sandbox",
            "repairAvailable": False,
            "mode": "off",
            "backend": "docker",
            "dockerAvailable": None,
            "warnings": [],
        }
    try:
        raw_snapshot = build_snapshot()
    except Exception as exc:  # pragma: no cover - defensive adapter boundary
        return {
            "status": "unavailable",
            "summary": f"Gateway config could not be read: {exc}",
            "source": "openzues-native",
            "openClawContribution": "doctor:sandbox",
            "repairAvailable": False,
            "mode": "off",
            "backend": "docker",
            "dockerAvailable": None,
            "warnings": [],
        }
    snapshot = raw_snapshot if isinstance(raw_snapshot, dict) else {}
    sandbox_config = _doctor_sandbox_config_from_snapshot(snapshot)
    mode = _doctor_sandbox_mode(
        sandbox_config.get("mode") if isinstance(sandbox_config, dict) else None
    )
    backend = _doctor_sandbox_backend(
        sandbox_config.get("backend") if isinstance(sandbox_config, dict) else None
    )
    scope_warnings = _doctor_sandbox_scope_warnings_from_snapshot(snapshot)
    base_payload: dict[str, object] = {
        "source": "openzues-native",
        "openClawContribution": "doctor:sandbox",
        "repairAvailable": False,
        "mode": mode,
        "backend": backend,
        "warnings": scope_warnings,
    }
    if mode == "off" or sandbox_config is None:
        return {
            **base_payload,
            "status": "ok",
            "summary": "Sandbox mode is off.",
            "dockerAvailable": None,
        }
    if backend != "docker":
        warning = None
        browser_config = sandbox_config.get("browser")
        if isinstance(browser_config, dict) and browser_config.get("enabled") is True:
            warning = (
                f'Sandbox backend "{backend}" selected. Docker browser health checks are '
                "skipped; browser sandbox currently requires the docker backend."
            )
        warnings = [*scope_warnings, warning] if warning else scope_warnings
        return {
            **base_payload,
            "status": "warn" if warning else "ok",
            "summary": warning or f'Sandbox backend "{backend}" selected.',
            "dockerAvailable": None,
            "warnings": warnings,
        }
    docker_available = _sandbox_docker_available()
    if not docker_available:
        warning = _doctor_sandbox_docker_unavailable_warning(mode)
        return {
            **base_payload,
            "status": "error",
            "summary": f'Sandbox mode is enabled (mode: "{mode}") but Docker is not available.',
            "dockerAvailable": False,
            "warnings": [*scope_warnings, warning],
        }
    return {
        **base_payload,
        "status": "ok",
        "summary": f'Sandbox Docker backend is available for mode "{mode}".',
        "dockerAvailable": True,
    }


def _with_doctor_sandbox_payload(
    payload: dict[str, object],
    config_service: object | None,
) -> dict[str, object]:
    next_payload = dict(payload)
    next_payload["sandbox"] = _build_doctor_sandbox_payload(config_service)
    return next_payload


_SESSION_LOCK_STALE_SECONDS = 30 * 60


def _doctor_state_directory_payload(data_dir: Path) -> dict[str, object]:
    path_text = str(data_dir)
    if data_dir.exists() and data_dir.is_dir():
        return {
            "ok": True,
            "path": path_text,
            "severity": "ok",
            "warnings": [],
        }
    return {
        "ok": False,
        "path": path_text,
        "severity": "critical",
        "warnings": [f"CRITICAL: state directory missing: {path_text}"],
    }


def _with_doctor_state_directory_health(
    payload: dict[str, object],
    data_dir: Path,
) -> dict[str, object]:
    next_payload = dict(payload)
    state_payload = _doctor_state_directory_payload(data_dir)
    next_payload["stateDirectory"] = state_payload
    warnings = _object_list(state_payload.get("warnings"))
    if warnings:
        next_payload = _with_doctor_added_warnings(
            next_payload,
            [str(warning) for warning in warnings],
        )
    return next_payload


def _doctor_session_lock_payload(
    data_dir: Path,
    *,
    should_repair: bool = False,
) -> dict[str, object] | None:
    lock_paths = sorted((data_dir / "agents").glob("*/sessions/*.jsonl.lock"))
    if not lock_paths:
        return None
    locks: list[dict[str, object]] = []
    removed_count = 0
    for lock_path in lock_paths:
        lock = _doctor_session_lock_record(lock_path)
        if should_repair and lock.get("stale") is True:
            try:
                lock_path.unlink(missing_ok=True)
                lock["removed"] = True
                removed_count += 1
            except OSError as exc:
                lock["removeError"] = str(exc)
        locks.append(lock)
    stale_count = sum(1 for lock in locks if lock.get("stale") is True)
    lines = [
        f"- Found {len(locks)} session lock file{'s' if len(locks) != 1 else ''}.",
        *[_doctor_session_lock_line(lock) for lock in locks],
    ]
    if stale_count and not should_repair:
        lines.append(f"- {stale_count} lock file{'s are' if stale_count != 1 else ' is'} stale.")
        lines.append('- Run "openzues doctor --fix" to remove stale lock files automatically.')
    if should_repair and removed_count:
        lines.append(
            f"- Removed {removed_count} stale session lock "
            f"file{'s' if removed_count != 1 else ''}."
        )
    return {
        "summary": lines[0][2:],
        "count": len(locks),
        "staleCount": stale_count,
        "removedCount": removed_count,
        "locks": locks,
        "lines": lines,
    }


def _doctor_session_lock_record(lock_path: Path) -> dict[str, object]:
    raw_payload: object = {}
    try:
        raw_payload = json.loads(lock_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        raw_payload = {}
    payload = raw_payload if isinstance(raw_payload, dict) else {}
    pid = _doctor_session_lock_pid(payload.get("pid"))
    age_seconds = _doctor_session_lock_age_seconds(payload.get("createdAt"))
    pid_alive = _doctor_session_lock_pid_alive(pid)
    stale_reasons: list[str] = []
    if pid is None:
        stale_reasons.append("missing pid")
    elif not pid_alive:
        stale_reasons.append("dead pid")
    if age_seconds is None:
        stale_reasons.append("unknown age")
    elif age_seconds >= _SESSION_LOCK_STALE_SECONDS:
        stale_reasons.append("old")
    return {
        "path": str(lock_path),
        "pid": pid,
        "pidAlive": pid_alive,
        "ageSeconds": age_seconds,
        "stale": bool(stale_reasons),
        "staleReasons": stale_reasons,
        "removed": False,
    }


def _doctor_session_lock_line(lock: dict[str, object]) -> str:
    path = str(lock.get("path") or "")
    pid = lock.get("pid")
    if isinstance(pid, int):
        pid_status = f"pid={pid} ({'alive' if lock.get('pidAlive') is True else 'dead'})"
    else:
        pid_status = "pid=missing"
    age_status = f"age={_doctor_session_lock_age_label(lock.get('ageSeconds'))}"
    raw_stale_reasons = lock.get("staleReasons")
    stale_reasons = raw_stale_reasons if isinstance(raw_stale_reasons, list) else ["unknown"]
    stale_status = (
        "stale=yes (" + ", ".join(str(reason) for reason in stale_reasons or ["unknown"]) + ")"
        if lock.get("stale") is True
        else "stale=no"
    )
    removed_status = " [removed]" if lock.get("removed") is True else ""
    return f"- {path} {pid_status} {age_status} {stale_status}{removed_status}"


def _doctor_session_lock_pid(value: object) -> int | None:
    if isinstance(value, bool):
        return None
    if isinstance(value, int):
        return value if value > 0 else None
    if not isinstance(value, str):
        return None
    try:
        pid = int(value)
    except ValueError:
        return None
    return pid if pid > 0 else None


def _doctor_session_lock_pid_alive(pid: int | None) -> bool:
    if pid is None:
        return False
    if pid == os.getpid():
        return True
    if sys.platform == "win32":
        try:
            result = subprocess.run(
                ["tasklist", "/FI", f"PID eq {pid}", "/FO", "CSV", "/NH"],
                capture_output=True,
                check=False,
                text=True,
                timeout=3,
            )
        except (OSError, subprocess.SubprocessError):
            return False
        output = (result.stdout or "").strip().lower()
        return result.returncode == 0 and str(pid) in output and "no tasks" not in output
    try:
        os.kill(pid, 0)
    except OSError:
        return False
    return True


def _doctor_session_lock_age_seconds(value: object) -> int | None:
    if not isinstance(value, str) or not value.strip():
        return None
    text = value.strip().replace("Z", "+00:00")
    try:
        created_at = datetime.fromisoformat(text)
    except ValueError:
        return None
    if created_at.tzinfo is None:
        created_at = created_at.replace(tzinfo=UTC)
    age = datetime.now(UTC) - created_at.astimezone(UTC)
    return max(0, int(age.total_seconds()))


def _doctor_session_lock_age_label(value: object) -> str:
    if not isinstance(value, int):
        return "unknown"
    if value < 60:
        return f"{value}s"
    minutes, seconds = divmod(value, 60)
    if minutes < 60:
        return f"{minutes}m{seconds}s"
    hours, remaining_minutes = divmod(minutes, 60)
    return f"{hours}h{remaining_minutes}m"


def _with_doctor_session_lock_health(
    payload: dict[str, object],
    data_dir: Path,
    *,
    should_repair: bool = False,
) -> dict[str, object]:
    session_locks = _doctor_session_lock_payload(data_dir, should_repair=should_repair)
    if session_locks is None:
        return payload
    next_payload = dict(payload)
    next_payload["session_locks"] = session_locks
    return next_payload


_LEGACY_CRON_ISSUE_LABELS: dict[str, str] = {
    "jobId": "still uses legacy `jobId`",
    "legacyScheduleString": "stores schedule as a bare string",
    "legacyScheduleCron": "still uses `schedule.cron`",
    "legacyPayloadKind": "needs payload kind normalization",
    "legacyPayloadProvider": "still uses payload `provider` as a delivery alias",
    "legacyTopLevelPayloadFields": "still uses top-level payload fields",
    "legacyTopLevelDeliveryFields": "still uses top-level delivery fields",
    "legacyDeliveryMode": "still uses delivery mode `deliver`",
    "legacyNotify": "still uses legacy `notify: true` webhook fallback",
}


def _doctor_cron_store_path(snapshot: dict[str, object]) -> Path | None:
    cron = _dict_config(snapshot.get("cron"))
    store_path = _optional_cli_string(cron.get("store"))
    if store_path is None:
        return None
    expanded = os.path.expandvars(os.path.expanduser(store_path))
    try:
        return Path(expanded).resolve(strict=False)
    except OSError:
        return Path(expanded)


def _doctor_cron_webhook(snapshot: dict[str, object]) -> str | None:
    cron = _dict_config(snapshot.get("cron"))
    return _optional_cli_string(cron.get("webhook")) or _optional_cli_string(
        cron.get("webhookUrl")
    )


def _legacy_cron_increment(issues: dict[str, int], key: str) -> None:
    issues[key] = issues.get(key, 0) + 1


def _legacy_cron_track_issue(
    issues: dict[str, int],
    seen: set[str],
    key: str,
) -> None:
    if key in seen:
        return
    seen.add(key)
    _legacy_cron_increment(issues, key)


def _legacy_cron_plural(count: int, noun: str) -> str:
    return f"{count} {noun}{'' if count == 1 else 's'}"


def _doctor_legacy_cron_payload_record(job: dict[str, object]) -> dict[str, object] | None:
    payload = job.get("payload")
    return payload if isinstance(payload, dict) else None


def _doctor_legacy_cron_delivery_record(job: dict[str, object]) -> dict[str, object] | None:
    delivery = job.get("delivery")
    return delivery if isinstance(delivery, dict) else None


def _doctor_legacy_cron_set_payload_from_top_level(job: dict[str, object]) -> bool:
    if isinstance(job.get("payload"), dict):
        return False
    message = _optional_cli_string(job.get("message"))
    if message is not None:
        job["payload"] = {"kind": "agentTurn", "message": message}
        return True
    text = _optional_cli_string(job.get("text"))
    if text is not None:
        job["payload"] = {"kind": "systemEvent", "text": text}
        return True
    command = _optional_cli_string(job.get("command"))
    if command is not None:
        job["payload"] = {"kind": "systemEvent", "text": command}
        return True
    return False


def _doctor_legacy_cron_normalize_payload_kind(payload: dict[str, object]) -> bool:
    kind = _optional_cli_string(payload.get("kind"))
    normalized = (kind or "").replace(" ", "").lower()
    if normalized == "agentturn" and payload.get("kind") != "agentTurn":
        payload["kind"] = "agentTurn"
        return True
    if normalized == "systemevent" and payload.get("kind") != "systemEvent":
        payload["kind"] = "systemEvent"
        return True
    if not kind:
        if _optional_cli_string(payload.get("message")) is not None:
            payload["kind"] = "agentTurn"
            return True
        if _optional_cli_string(payload.get("text")) is not None:
            payload["kind"] = "systemEvent"
            return True
    return False


def _doctor_legacy_cron_copy_payload_fields(
    job: dict[str, object],
    payload: dict[str, object],
) -> bool:
    changed = False
    for field in ("model", "thinking"):
        value = _optional_cli_string(job.get(field))
        if value is not None and _optional_cli_string(payload.get(field)) is None:
            payload[field] = value
            changed = True
    timeout = job.get("timeoutSeconds")
    if (
        isinstance(timeout, int | float)
        and not isinstance(timeout, bool)
        and "timeoutSeconds" not in payload
    ):
        payload["timeoutSeconds"] = max(0, int(timeout))
        changed = True
    return changed


def _doctor_legacy_cron_strip_fields(job: dict[str, object], fields: Sequence[str]) -> None:
    for field in fields:
        job.pop(field, None)


def _doctor_legacy_cron_delivery_from_top_level(
    job: dict[str, object],
) -> dict[str, object] | None:
    deliver = job.get("deliver")
    channel = _optional_cli_string(job.get("channel")) or _optional_cli_string(
        job.get("provider")
    )
    to = _optional_cli_string(job.get("to"))
    thread_id = _optional_cli_string(job.get("threadId"))
    best_effort = job.get("bestEffortDeliver")
    if deliver is not True and channel is None and to is None and thread_id is None:
        return None
    delivery: dict[str, object] = {"mode": "announce"}
    if channel is not None:
        delivery["channel"] = channel.lower()
    if to is not None:
        delivery["to"] = to
    if thread_id is not None:
        delivery["threadId"] = thread_id
    if isinstance(best_effort, bool):
        delivery["bestEffort"] = best_effort
    return delivery


def _doctor_legacy_cron_migrate_notify(
    job: dict[str, object],
    *,
    legacy_webhook: str | None,
) -> tuple[bool, list[str]]:
    if "notify" not in job:
        return False, []
    changed = False
    warnings: list[str] = []
    job_name = _optional_cli_string(job.get("name")) or _optional_cli_string(job.get("id")) or (
        "<unnamed>"
    )
    if job.get("notify") is not True:
        job.pop("notify", None)
        return True, warnings
    delivery = _doctor_legacy_cron_delivery_record(job)
    mode = _optional_cli_string(delivery.get("mode") if delivery else None)
    to = _optional_cli_string(delivery.get("to") if delivery else None)
    normalized_mode = mode.lower() if mode is not None else None
    if normalized_mode == "webhook" and to is not None:
        job.pop("notify", None)
        return True, warnings
    if normalized_mode in {None, "none", "webhook"} and legacy_webhook is not None:
        next_delivery = dict(delivery or {})
        next_delivery["mode"] = "webhook"
        next_delivery["to"] = (
            legacy_webhook if normalized_mode == "none" else (to or legacy_webhook)
        )
        job["delivery"] = next_delivery
        job.pop("notify", None)
        return True, warnings
    if legacy_webhook is None:
        warnings.append(
            f'Cron job "{job_name}" still uses legacy notify fallback, but cron.webhook '
            "is unset so doctor cannot migrate it automatically."
        )
        return changed, warnings
    warnings.append(
        f'Cron job "{job_name}" uses legacy notify fallback alongside delivery mode '
        f'"{normalized_mode}". Migrate it manually so webhook delivery does not replace '
        "existing announce behavior."
    )
    return changed, warnings


def _doctor_legacy_cron_normalize_jobs(
    jobs: Sequence[object],
    *,
    legacy_webhook: str | None,
) -> tuple[bool, dict[str, int], list[str]]:
    changed = False
    issues: dict[str, int] = {}
    warnings: list[str] = []
    for item in jobs:
        if not isinstance(item, dict):
            continue
        job = cast("dict[str, object]", item)
        job_issue_keys: set[str] = set()

        legacy_id = _optional_cli_string(job.get("jobId"))
        if legacy_id is not None:
            if _optional_cli_string(job.get("id")) is None:
                job["id"] = legacy_id
            job.pop("jobId", None)
            changed = True
            _legacy_cron_track_issue(issues, job_issue_keys, "jobId")

        if not isinstance(job.get("state"), dict):
            job["state"] = {}
            changed = True

        schedule = job.get("schedule")
        if isinstance(schedule, str):
            job["schedule"] = {"kind": "cron", "expr": schedule.strip()}
            changed = True
            _legacy_cron_track_issue(issues, job_issue_keys, "legacyScheduleString")
            schedule = job.get("schedule")
        if isinstance(schedule, dict):
            sched = cast("dict[str, object]", schedule)
            legacy_cron = _optional_cli_string(sched.get("cron"))
            if legacy_cron is not None:
                if _optional_cli_string(sched.get("expr")) is None:
                    sched["expr"] = legacy_cron
                sched.pop("cron", None)
                changed = True
                _legacy_cron_track_issue(issues, job_issue_keys, "legacyScheduleCron")

        if _doctor_legacy_cron_set_payload_from_top_level(job):
            changed = True
            _legacy_cron_track_issue(issues, job_issue_keys, "legacyTopLevelPayloadFields")
        payload = _doctor_legacy_cron_payload_record(job)
        if payload is not None:
            if _doctor_legacy_cron_normalize_payload_kind(payload):
                changed = True
                _legacy_cron_track_issue(issues, job_issue_keys, "legacyPayloadKind")
            if _doctor_legacy_cron_copy_payload_fields(job, payload):
                changed = True

            payload_provider = _optional_cli_string(payload.get("provider"))
            if payload_provider is not None:
                job["delivery"] = {"mode": "announce", "channel": payload_provider.lower()}
                payload.pop("provider", None)
                changed = True
                _legacy_cron_track_issue(issues, job_issue_keys, "legacyPayloadProvider")

        top_level_payload_fields = (
            "model",
            "thinking",
            "timeoutSeconds",
            "allowUnsafeExternalContent",
            "message",
            "text",
            "command",
            "timeout",
        )
        if any(field in job for field in top_level_payload_fields):
            _doctor_legacy_cron_strip_fields(job, top_level_payload_fields)
            changed = True
            _legacy_cron_track_issue(issues, job_issue_keys, "legacyTopLevelPayloadFields")

        top_level_delivery_fields = (
            "deliver",
            "channel",
            "to",
            "threadId",
            "bestEffortDeliver",
            "provider",
        )
        delivery = _doctor_legacy_cron_delivery_from_top_level(job)
        if delivery is not None:
            job["delivery"] = delivery
            changed = True
        if any(field in job for field in top_level_delivery_fields):
            _doctor_legacy_cron_strip_fields(job, top_level_delivery_fields)
            changed = True
            _legacy_cron_track_issue(issues, job_issue_keys, "legacyTopLevelDeliveryFields")

        if job.get("notify") is True:
            _legacy_cron_track_issue(issues, job_issue_keys, "legacyNotify")
        notify_changed, notify_warnings = _doctor_legacy_cron_migrate_notify(
            job,
            legacy_webhook=legacy_webhook,
        )
        changed = changed or notify_changed
        warnings.extend(notify_warnings)
    return changed, issues, warnings


def _doctor_legacy_cron_preview_lines(
    store_path: Path,
    issues: dict[str, int],
) -> list[str]:
    if not issues:
        return []
    lines = [f"Legacy cron job storage detected at {store_path}."]
    for key, label in _LEGACY_CRON_ISSUE_LABELS.items():
        count = issues.get(key)
        if not count:
            continue
        lines.append(f"- {_legacy_cron_plural(count, 'job')} {label}")
    lines.append('Repair with "openzues doctor --fix" to normalize the store.')
    return lines


def _build_doctor_legacy_cron_payload(
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    base_payload: dict[str, object] = {
        "source": "openzues-native",
        "openClawContribution": "doctor:legacy-cron",
        "repairRequested": should_repair,
        "repairAvailable": True,
        "issues": {},
        "warnings": [],
    }
    snapshot = _doctor_config_snapshot(config_service)
    store_path = _doctor_cron_store_path(snapshot)
    if store_path is None:
        return {
            **base_payload,
            "status": "ok",
            "summary": "No legacy cron store configured.",
            "repairAvailable": False,
        }
    raw_store = _read_cli_json_object(store_path)
    if raw_store is None:
        return {
            **base_payload,
            "status": "ok" if not store_path.exists() else "error",
            "summary": (
                "No legacy cron store found."
                if not store_path.exists()
                else f"Legacy cron store could not be read: {store_path}"
            ),
            "storePath": str(store_path),
        }
    jobs = _object_list(raw_store.get("jobs"))
    changed, issues, migration_warnings = _doctor_legacy_cron_normalize_jobs(
        jobs,
        legacy_webhook=_doctor_cron_webhook(snapshot),
    )
    preview_lines = _doctor_legacy_cron_preview_lines(store_path, issues)
    if should_repair:
        changes: list[str] = []
        errors: list[str] = []
        if changed:
            try:
                store_path.parent.mkdir(parents=True, exist_ok=True)
                next_store = {"version": raw_store.get("version", 1), "jobs": jobs}
                store_path.write_text(
                    f"{json.dumps(next_store, indent=2)}\n",
                    encoding="utf-8",
                )
                changes.append(f"Cron store normalized at {store_path}.")
            except OSError as exc:
                errors.append(f"Failed to normalize legacy cron store at {store_path}: {exc}")
        warnings = migration_warnings if errors else migration_warnings
        return {
            **base_payload,
            "status": "error" if errors else ("ok" if changed or not issues else "warn"),
            "summary": (
                "Cron store normalized."
                if changed and not errors
                else (
                    "Legacy cron store repair had errors."
                    if errors
                    else (
                        "Legacy cron store still needs manual migration."
                        if issues
                        else "No legacy cron store issues found."
                    )
                )
            ),
            "changed": changed and not errors,
            "changes": changes,
            "errors": errors,
            "issues": issues,
            "warnings": warnings,
            "storePath": str(store_path),
        }
    return {
        **base_payload,
        "status": "warn" if issues else "ok",
        "summary": (
            "Legacy cron job storage found." if issues else "No legacy cron store issues found."
        ),
        "issues": issues,
        "warnings": [*preview_lines, *migration_warnings],
        "storePath": str(store_path),
    }


def _with_doctor_legacy_cron_payload(
    payload: dict[str, object],
    config_service: object | None,
    *,
    should_repair: bool,
) -> dict[str, object]:
    cron_payload = _build_doctor_legacy_cron_payload(
        config_service,
        should_repair=should_repair,
    )
    next_payload = dict(payload)
    next_payload["legacyCron"] = cron_payload
    warnings = _object_list(cron_payload.get("warnings"))
    if warnings:
        next_payload = _with_doctor_added_warnings(next_payload, [str(item) for item in warnings])
    return next_payload


def _doctor_security_snapshot(config_service: object | None) -> dict[str, object] | None:
    build_snapshot = getattr(config_service, "build_snapshot", None)
    if not callable(build_snapshot):
        return None
    try:
        snapshot = build_snapshot()
    except Exception:
        return None
    return snapshot if isinstance(snapshot, dict) else None


def _doctor_security_approvals_warnings(snapshot: dict[str, object]) -> list[str]:
    approvals = snapshot.get("approvals")
    if not isinstance(approvals, dict):
        return []
    exec_config = approvals.get("exec")
    if not isinstance(exec_config, dict):
        return []
    if exec_config.get("enabled") is not False:
        return []
    return [
        "\n".join(
            [
                "- Note: approvals.exec.enabled=false disables approval forwarding only.",
                "  Host exec gating still comes from ~/.openclaw/exec-approvals.json.",
                "  Check local policy with: openclaw approvals get --gateway",
            ]
        )
    ]


def _doctor_security_heartbeat_warning(
    *,
    label: str,
    heartbeat: object,
    path_hint: str,
) -> str | None:
    if not isinstance(heartbeat, dict):
        return None
    target = heartbeat.get("target")
    if target is None or target == "none":
        return None
    if "directPolicy" in heartbeat:
        return None
    return "\n".join(
        [
            f"- {label}: heartbeat delivery is configured while {path_hint} is unset.",
            '  Heartbeat now allows direct/DM targets by default. Set it explicitly to '
            '"allow" or "block" to pin upgrade behavior.',
        ]
    )


def _doctor_security_heartbeat_warnings(snapshot: dict[str, object]) -> list[str]:
    agents = snapshot.get("agents")
    if not isinstance(agents, dict):
        return []
    warnings: list[str] = []
    defaults = agents.get("defaults")
    if isinstance(defaults, dict):
        warning = _doctor_security_heartbeat_warning(
            label="Heartbeat defaults",
            heartbeat=defaults.get("heartbeat"),
            path_hint="agents.defaults.heartbeat.directPolicy",
        )
        if warning is not None:
            warnings.append(warning)
    for agent in _object_list(agents.get("list")):
        if not isinstance(agent, dict):
            continue
        agent_id = _optional_cli_string(agent.get("id"))
        if agent_id is None:
            continue
        warning = _doctor_security_heartbeat_warning(
            label=f'Heartbeat agent "{agent_id}"',
            heartbeat=agent.get("heartbeat"),
            path_hint=f'heartbeat.directPolicy for agent "{agent_id}"',
        )
        if warning is not None:
            warnings.append(warning)
    return warnings


_DOCTOR_EXEC_SECURITY_RANK = {"deny": 0, "allowlist": 1, "full": 2}
_DOCTOR_EXEC_ASK_RANK = {"off": 0, "on-miss": 1, "always": 2}
_DOCTOR_EXEC_DEFAULT_SECURITY = "full"
_DOCTOR_EXEC_DEFAULT_ASK = "off"
_DOCTOR_DEFAULT_SAFE_BIN_TRUSTED_DIRS = ("/bin", "/usr/bin")
_DOCTOR_INTERPRETER_LIKE_SAFE_BINS = {
    "ash",
    "awk",
    "bash",
    "busybox",
    "bun",
    "cmd",
    "cmd.exe",
    "cscript",
    "dash",
    "deno",
    "fish",
    "gawk",
    "gsed",
    "ksh",
    "lua",
    "mawk",
    "nawk",
    "node",
    "nodejs",
    "perl",
    "php",
    "powershell",
    "powershell.exe",
    "pypy",
    "pwsh",
    "pwsh.exe",
    "python",
    "python2",
    "python3",
    "ruby",
    "sed",
    "sh",
    "toybox",
    "wscript",
    "zsh",
}
_DOCTOR_RISKY_SAFE_BIN_WARNINGS = {
    "awk": (
        "awk-family interpreters can execute commands, access ENVIRON, and write files, "
        "so prefer explicit allowlist entries or approval-gated runs instead of safeBins."
    ),
    "gawk": (
        "awk-family interpreters can execute commands, access ENVIRON, and write files, "
        "so prefer explicit allowlist entries or approval-gated runs instead of safeBins."
    ),
    "mawk": (
        "awk-family interpreters can execute commands, access ENVIRON, and write files, "
        "so prefer explicit allowlist entries or approval-gated runs instead of safeBins."
    ),
    "nawk": (
        "awk-family interpreters can execute commands, access ENVIRON, and write files, "
        "so prefer explicit allowlist entries or approval-gated runs instead of safeBins."
    ),
    "jq": (
        "jq supports broad jq programs and builtins (for example `env`), so prefer "
        "explicit allowlist entries or approval-gated runs instead of safeBins."
    ),
    "sed": (
        "sed scripts can execute commands and write files, so prefer explicit allowlist "
        "entries or approval-gated runs instead of safeBins."
    ),
    "gsed": (
        "sed scripts can execute commands and write files, so prefer explicit allowlist "
        "entries or approval-gated runs instead of safeBins."
    ),
}
_DOCTOR_INTERPRETER_LIKE_SAFE_BIN_PATTERNS = (
    re.compile(r"^python\d+(?:\.\d+)?$"),
    re.compile(r"^ruby\d+(?:\.\d+)?$"),
    re.compile(r"^perl\d+(?:\.\d+)?$"),
    re.compile(r"^php\d+(?:\.\d+)?$"),
    re.compile(r"^node\d+(?:\.\d+)?$"),
)


def _doctor_exec_security_value(value: object) -> str | None:
    text = _optional_cli_string(value)
    if text is None:
        return None
    normalized = text.lower()
    return normalized if normalized in _DOCTOR_EXEC_SECURITY_RANK else None


def _doctor_exec_ask_value(value: object) -> str | None:
    text = _optional_cli_string(value)
    if text is None:
        return None
    normalized = text.lower()
    return normalized if normalized in _DOCTOR_EXEC_ASK_RANK else None


def _doctor_exec_policy_config(value: object) -> dict[str, str]:
    config = _dict_config(value)
    resolved: dict[str, str] = {}
    security = _doctor_exec_security_value(config.get("security"))
    if security is not None:
        resolved["security"] = security
    ask = _doctor_exec_ask_value(config.get("ask"))
    if ask is not None:
        resolved["ask"] = ask
    return resolved


def _doctor_normalize_safe_bin_name(value: object) -> str | None:
    text = _optional_cli_string(value)
    if text is None:
        return None
    tail = re.split(r"[\\/]", text.lower())[-1]
    normalized = re.sub(r"\.(?:exe|cmd|bat|com)$", "", tail)
    return normalized or None


def _doctor_safe_bin_list(value: object) -> list[str]:
    if not isinstance(value, list):
        return []
    normalized = [
        name
        for item in value
        if (name := _doctor_normalize_safe_bin_name(item)) is not None
    ]
    return sorted(_dedupe_cli_strings(normalized))


def _doctor_safe_bin_profiles(value: object) -> dict[str, object]:
    profiles = _dict_config(value)
    return {
        name: profile
        for key, profile in profiles.items()
        if (name := _doctor_normalize_safe_bin_name(key)) is not None
    }


def _doctor_safe_bin_trusted_dirs(value: object) -> list[Path]:
    dirs: list[Path] = []
    if not isinstance(value, list):
        return dirs
    for entry in value:
        path_text = _optional_cli_string(entry)
        if path_text is None:
            continue
        dirs.append(_bundled_lookup_path(path_text))
    return dirs


def _doctor_is_interpreter_like_safe_bin(bin_name: str) -> bool:
    if bin_name in _DOCTOR_INTERPRETER_LIKE_SAFE_BINS:
        return True
    return any(
        pattern.match(bin_name) is not None
        for pattern in _DOCTOR_INTERPRETER_LIKE_SAFE_BIN_PATTERNS
    )


def _doctor_exec_safe_bin_scopes(
    snapshot: dict[str, object],
) -> list[tuple[str, list[str], dict[str, object], list[Path]]]:
    scopes: list[tuple[str, list[str], dict[str, object], list[Path]]] = []
    tools = _dict_config(snapshot.get("tools"))
    global_exec = _dict_config(tools.get("exec"))
    global_safe_bins = _doctor_safe_bin_list(global_exec.get("safeBins"))
    global_profiles = _doctor_safe_bin_profiles(global_exec.get("safeBinProfiles"))
    default_trusted_dirs = [
        _bundled_lookup_path(path_text) for path_text in _DOCTOR_DEFAULT_SAFE_BIN_TRUSTED_DIRS
    ]
    global_trusted_dirs = [
        *default_trusted_dirs,
        *_doctor_safe_bin_trusted_dirs(global_exec.get("safeBinTrustedDirs")),
    ]
    if global_safe_bins:
        scopes.append(("tools.exec", global_safe_bins, global_profiles, global_trusted_dirs))
    agents = _dict_config(snapshot.get("agents"))
    for agent in _object_list(agents.get("list")):
        if not isinstance(agent, dict):
            continue
        agent_id = _optional_cli_string(agent.get("id"))
        if agent_id is None:
            continue
        agent_tools = _dict_config(agent.get("tools"))
        agent_exec = _dict_config(agent_tools.get("exec"))
        agent_safe_bins = _doctor_safe_bin_list(agent_exec.get("safeBins"))
        if not agent_safe_bins:
            continue
        agent_profiles = {
            **global_profiles,
            **_doctor_safe_bin_profiles(agent_exec.get("safeBinProfiles")),
        }
        agent_trusted_dirs = [
            *global_trusted_dirs,
            *_doctor_safe_bin_trusted_dirs(agent_exec.get("safeBinTrustedDirs")),
        ]
        scopes.append(
            (
                f"agents.list.{agent_id}.tools.exec",
                agent_safe_bins,
                agent_profiles,
                agent_trusted_dirs,
            )
        )
    return scopes


def _doctor_exec_safe_bin_coverage_hits(
    snapshot: dict[str, object],
) -> list[dict[str, object]]:
    hits: list[dict[str, object]] = []
    for scope_path, safe_bins, merged_profiles, _trusted_dirs in _doctor_exec_safe_bin_scopes(
        snapshot
    ):
        for bin_name in safe_bins:
            if bin_name in merged_profiles:
                continue
            hits.append(
                {
                    "scopePath": scope_path,
                    "bin": bin_name,
                    "kind": "missingProfile",
                    "isInterpreter": _doctor_is_interpreter_like_safe_bin(bin_name),
                }
            )
        for bin_name in safe_bins:
            warning = _DOCTOR_RISKY_SAFE_BIN_WARNINGS.get(bin_name)
            if warning is None:
                continue
            hits.append(
                {
                    "scopePath": scope_path,
                    "bin": bin_name,
                    "kind": "riskySemantics",
                    "warning": warning,
                }
            )
    return hits


def _doctor_is_trusted_safe_bin_path(
    resolved_path: Path,
    trusted_dirs: Sequence[Path],
) -> bool:
    try:
        resolved_parent = resolved_path.resolve(strict=False).parent
    except OSError:
        resolved_parent = resolved_path.parent
    return any(resolved_parent == trusted_dir for trusted_dir in trusted_dirs)


def _doctor_exec_safe_bin_trusted_dir_hints(
    snapshot: dict[str, object],
) -> list[dict[str, object]]:
    hints: list[dict[str, object]] = []
    for scope_path, safe_bins, _merged_profiles, trusted_dirs in _doctor_exec_safe_bin_scopes(
        snapshot
    ):
        for bin_name in safe_bins:
            resolved = shutil.which(bin_name)
            if resolved is None:
                continue
            resolved_path = _bundled_lookup_path(resolved)
            if _doctor_is_trusted_safe_bin_path(resolved_path, trusted_dirs):
                continue
            hints.append(
                {
                    "scopePath": scope_path,
                    "bin": bin_name,
                    "resolvedPath": str(resolved_path),
                }
            )
    return hints


def _doctor_exec_safe_bin_warnings(hits: Sequence[dict[str, object]]) -> list[str]:
    if not hits:
        return []
    warnings: list[str] = []
    interpreter_hits = [
        hit
        for hit in hits
        if hit.get("kind") == "missingProfile" and hit.get("isInterpreter") is True
    ]
    custom_hits = [
        hit
        for hit in hits
        if hit.get("kind") == "missingProfile" and hit.get("isInterpreter") is not True
    ]
    risky_hits = [hit for hit in hits if hit.get("kind") == "riskySemantics"]
    for hit in interpreter_hits[:5]:
        warnings.append(
            f"- {hit.get('scopePath')}.safeBins includes interpreter/runtime "
            f"'{hit.get('bin')}' without profile."
        )
    if len(interpreter_hits) > 5:
        warnings.append(
            f"- {len(interpreter_hits) - 5} more interpreter/runtime safeBins "
            "entries are missing profiles."
        )
    for hit in custom_hits[:5]:
        warnings.append(
            f"- {hit.get('scopePath')}.safeBins entry '{hit.get('bin')}' is "
            f"missing safeBinProfiles.{hit.get('bin')}."
        )
    if len(custom_hits) > 5:
        warnings.append(
            f"- {len(custom_hits) - 5} more custom safeBins entries are missing profiles."
        )
    for hit in risky_hits[:5]:
        warning = hit.get("warning") or (
            "prefer explicit allowlist entries or approval-gated runs."
        )
        warnings.append(
            f"- {hit.get('scopePath')}.safeBins includes '{hit.get('bin')}': {warning}"
        )
    if len(risky_hits) > 5:
        warnings.append(
            f"- {len(risky_hits) - 5} more safeBins entries should not use the "
            "low-risk safeBins fast path."
        )
    if custom_hits:
        warnings.append(
            '- Run "openzues doctor --fix" to scaffold missing custom '
            "safeBinProfiles entries."
        )
    return warnings


def _doctor_exec_safe_bin_trusted_dir_warnings(
    hints: Sequence[dict[str, object]],
) -> list[str]:
    if not hints:
        return []
    warnings = [
        f"- {hint.get('scopePath')}.safeBins entry '{hint.get('bin')}' resolves to "
        f"'{hint.get('resolvedPath')}' outside trusted safe-bin dirs."
        for hint in hints[:5]
    ]
    if len(hints) > 5:
        warnings.append(
            f"- {len(hints) - 5} more safeBins entries resolve outside trusted "
            "safe-bin dirs."
        )
    warnings.append(
        "- If intentional, add the binary directory to tools.exec.safeBinTrustedDirs "
        "(global or agent scope)."
    )
    return warnings


def _doctor_exec_safe_bin_repair(
    snapshot: dict[str, object],
) -> tuple[dict[str, object], list[str]]:
    next_snapshot: dict[str, object] = dict(snapshot)
    changes: list[str] = []

    tools = dict(_dict_config(next_snapshot.get("tools")))
    global_exec = dict(_dict_config(tools.get("exec")))
    global_profiles = _doctor_safe_bin_profiles(global_exec.get("safeBinProfiles"))
    global_changed = False
    for bin_name in _doctor_safe_bin_list(global_exec.get("safeBins")):
        if bin_name in global_profiles or _doctor_is_interpreter_like_safe_bin(bin_name):
            continue
        global_profiles[bin_name] = {}
        global_changed = True
        changes.append(
            f"- tools.exec.safeBinProfiles.{bin_name}: added scaffold profile "
            "{} (review and tighten flags/positionals)."
        )
    if global_changed:
        global_exec["safeBinProfiles"] = global_profiles
        tools["exec"] = global_exec
        next_snapshot["tools"] = tools

    agents = dict(_dict_config(next_snapshot.get("agents")))
    raw_agent_list = agents.get("list")
    if not isinstance(raw_agent_list, list):
        return next_snapshot, changes

    next_agent_list: list[object] = []
    agent_list_changed = False
    for raw_agent in raw_agent_list:
        if not isinstance(raw_agent, dict):
            next_agent_list.append(raw_agent)
            continue
        agent_id = _optional_cli_string(raw_agent.get("id"))
        if agent_id is None:
            next_agent_list.append(raw_agent)
            continue
        agent_tools = dict(_dict_config(raw_agent.get("tools")))
        agent_exec = dict(_dict_config(agent_tools.get("exec")))
        agent_safe_bins = _doctor_safe_bin_list(agent_exec.get("safeBins"))
        if not agent_safe_bins:
            next_agent_list.append(raw_agent)
            continue
        local_profiles = _doctor_safe_bin_profiles(agent_exec.get("safeBinProfiles"))
        merged_profiles = {**global_profiles, **local_profiles}
        agent_changed = False
        for bin_name in agent_safe_bins:
            if bin_name in merged_profiles or _doctor_is_interpreter_like_safe_bin(bin_name):
                continue
            local_profiles[bin_name] = {}
            merged_profiles[bin_name] = {}
            agent_changed = True
            changes.append(
                f"- agents.list.{agent_id}.tools.exec.safeBinProfiles.{bin_name}: "
                "added scaffold profile {} (review and tighten flags/positionals)."
            )
        if not agent_changed:
            next_agent_list.append(raw_agent)
            continue
        agent_exec["safeBinProfiles"] = local_profiles
        agent_tools["exec"] = agent_exec
        next_agent = dict(raw_agent)
        next_agent["tools"] = agent_tools
        next_agent_list.append(next_agent)
        agent_list_changed = True
    if agent_list_changed:
        agents["list"] = next_agent_list
        next_snapshot["agents"] = agents
    return next_snapshot, changes


def _build_doctor_exec_safe_bins_payload(
    snapshot: dict[str, object],
    *,
    repair_requested: bool = False,
    changes: Sequence[str] = (),
) -> dict[str, object]:
    hits = _doctor_exec_safe_bin_coverage_hits(snapshot)
    trusted_dir_hints = _doctor_exec_safe_bin_trusted_dir_hints(snapshot)
    warnings = [
        *_doctor_exec_safe_bin_warnings(hits),
        *_doctor_exec_safe_bin_trusted_dir_warnings(trusted_dir_hints),
    ]
    custom_missing = any(
        hit.get("kind") == "missingProfile" and hit.get("isInterpreter") is not True
        for hit in hits
    )
    return {
        "status": "warning" if warnings else "ok",
        "summary": (
            "Exec safe-bin coverage has warnings."
            if warnings
            else "Exec safe-bin coverage has no warnings."
        ),
        "coverageHits": hits,
        "trustedDirHints": trusted_dir_hints,
        "warnings": warnings,
        "repairAvailable": bool(changes) or custom_missing,
        "repairRequested": repair_requested,
        "changed": bool(changes),
        "changes": list(changes),
        "openClawContribution": "doctor:exec-safe-bins",
    }


def _doctor_security_exec_approvals_path(data_dir: Path | None) -> Path:
    if data_dir is not None:
        return data_dir / "settings" / "exec-approvals.json"
    return Path.home() / ".openclaw" / "exec-approvals.json"


def _doctor_security_read_exec_approvals_file(
    data_dir: Path | None,
) -> tuple[Path, dict[str, object]]:
    path = _doctor_security_exec_approvals_path(data_dir)
    try:
        raw = path.read_text(encoding="utf-8")
        parsed = json.loads(raw)
    except (OSError, ValueError):
        return path, {"version": 1, "agents": {}}
    if not isinstance(parsed, dict) or parsed.get("version") != 1:
        return path, {"version": 1, "agents": {}}
    return path, parsed


def _doctor_exec_requested_field(
    *,
    scope_config: dict[str, str],
    global_config: dict[str, str],
    field: Literal["security", "ask"],
    config_path: str,
) -> tuple[str, str]:
    if field in scope_config:
        return scope_config[field], f"{config_path}.{field}"
    if field in global_config:
        return global_config[field], f"tools.exec.{field}"
    default_value = (
        _DOCTOR_EXEC_DEFAULT_SECURITY
        if field == "security"
        else _DOCTOR_EXEC_DEFAULT_ASK
    )
    return default_value, f"OpenClaw default ({default_value})"


def _doctor_exec_host_field(
    *,
    approvals_file: dict[str, object],
    approvals_path: Path,
    field: Literal["security", "ask"],
    requested: str,
    agent_id: str | None,
) -> tuple[str, str]:
    agents = _dict_config(approvals_file.get("agents"))
    if agent_id is not None:
        agent = _dict_config(agents.get(agent_id))
        value = (
            _doctor_exec_security_value(agent.get(field))
            if field == "security"
            else _doctor_exec_ask_value(agent.get(field))
        )
        if value is not None:
            return value, f"{approvals_path} agents.{agent_id}.{field}"
        wildcard = _dict_config(agents.get("*"))
        value = (
            _doctor_exec_security_value(wildcard.get(field))
            if field == "security"
            else _doctor_exec_ask_value(wildcard.get(field))
        )
        if value is not None:
            return value, f"{approvals_path} agents.*.{field}"

    defaults = _dict_config(approvals_file.get("defaults"))
    value = (
        _doctor_exec_security_value(defaults.get(field))
        if field == "security"
        else _doctor_exec_ask_value(defaults.get(field))
    )
    if value is not None:
        return value, f"{approvals_path} defaults.{field}"
    return requested, "inherits requested tool policy"


def _doctor_security_exec_policy_warning(
    *,
    scope_label: str,
    scope_config: dict[str, str],
    global_config: dict[str, str],
    approvals_file: dict[str, object],
    approvals_path: Path,
    agent_id: str | None = None,
) -> str | None:
    if not scope_config and not global_config:
        return None

    security_requested, security_requested_source = _doctor_exec_requested_field(
        scope_config=scope_config,
        global_config=global_config,
        field="security",
        config_path=scope_label,
    )
    ask_requested, ask_requested_source = _doctor_exec_requested_field(
        scope_config=scope_config,
        global_config=global_config,
        field="ask",
        config_path=scope_label,
    )
    security_host, security_host_source = _doctor_exec_host_field(
        approvals_file=approvals_file,
        approvals_path=approvals_path,
        field="security",
        requested=security_requested,
        agent_id=agent_id,
    )
    ask_host, ask_host_source = _doctor_exec_host_field(
        approvals_file=approvals_file,
        approvals_path=approvals_path,
        field="ask",
        requested=ask_requested,
        agent_id=agent_id,
    )
    security_effective = (
        security_requested
        if _DOCTOR_EXEC_SECURITY_RANK[security_requested]
        <= _DOCTOR_EXEC_SECURITY_RANK[security_host]
        else security_host
    )
    ask_effective = (
        ask_requested
        if _DOCTOR_EXEC_ASK_RANK[ask_requested] >= _DOCTOR_EXEC_ASK_RANK[ask_host]
        else ask_host
    )
    security_conflict = (
        security_requested_source != "OpenClaw default (full)"
        and _DOCTOR_EXEC_SECURITY_RANK[security_requested]
        > _DOCTOR_EXEC_SECURITY_RANK[security_effective]
    )
    ask_conflict = (
        ask_requested_source != "OpenClaw default (off)"
        and _DOCTOR_EXEC_ASK_RANK[ask_requested]
        < _DOCTOR_EXEC_ASK_RANK[ask_effective]
    )
    if not security_conflict and not ask_conflict:
        return None

    config_parts: list[str] = []
    host_parts: list[str] = []
    if security_conflict:
        config_parts.append(f'{security_requested_source}="{security_requested}"')
        host_parts.append(f'{security_host_source}="{security_host}"')
    if ask_conflict:
        config_parts.append(f'{ask_requested_source}="{ask_requested}"')
        host_parts.append(f'{ask_host_source}="{ask_host}"')
    return "\n".join(
        [
            f"- {scope_label} is broader than the host exec policy.",
            f"  Config: {', '.join(config_parts)}",
            f"  Host: {', '.join(host_parts)}",
            (
                f'  Effective host exec stays security="{security_effective}" '
                f'ask="{ask_effective}" because the stricter side wins.'
            ),
            (
                "  Headless runs like isolated cron cannot answer approval prompts; "
                "align both files or enable Web UI, terminal UI, or chat exec approvals."
            ),
            "  Inspect with: openclaw approvals get --gateway",
        ]
    )


def _doctor_security_exec_policy_warnings(
    snapshot: dict[str, object],
    data_dir: Path | None,
) -> list[str]:
    approvals_path, approvals_file = _doctor_security_read_exec_approvals_file(data_dir)
    tools = _dict_config(snapshot.get("tools"))
    global_config = _doctor_exec_policy_config(tools.get("exec"))
    warnings: list[str] = []
    global_warning = _doctor_security_exec_policy_warning(
        scope_label="tools.exec",
        scope_config=global_config,
        global_config={},
        approvals_file=approvals_file,
        approvals_path=approvals_path,
    )
    if global_warning is not None:
        warnings.append(global_warning)

    agents = _dict_config(snapshot.get("agents"))
    for agent in _object_list(agents.get("list")):
        if not isinstance(agent, dict):
            continue
        agent_id = _optional_cli_string(agent.get("id"))
        if agent_id is None:
            continue
        agent_tools = _dict_config(agent.get("tools"))
        agent_config = _doctor_exec_policy_config(agent_tools.get("exec"))
        agent_warning = _doctor_security_exec_policy_warning(
            scope_label=f"agents.list.{agent_id}.tools.exec",
            scope_config=agent_config,
            global_config=global_config,
            approvals_file=approvals_file,
            approvals_path=approvals_path,
            agent_id=agent_id,
        )
        if agent_warning is not None:
            warnings.append(agent_warning)
    return warnings


def _doctor_security_is_loopback_host(host: str) -> bool:
    normalized = host.strip().lower().strip("[]")
    return (
        normalized == "localhost"
        or normalized == "::1"
        or normalized.startswith("127.")
        or normalized in {"0:0:0:0:0:0:0:1", "::ffff:127.0.0.1"}
    )


def _doctor_security_gateway_bind_host(gateway: dict[str, object]) -> tuple[str, str]:
    bind = _optional_cli_string(gateway.get("bind")) or "loopback"
    if bind == "loopback":
        return bind, "127.0.0.1"
    if bind == "custom":
        return bind, _optional_cli_string(gateway.get("customBindHost")) or "0.0.0.0"
    if bind == "tailnet":
        return bind, "tailnet"
    if bind in {"auto", "lan"}:
        return bind, "0.0.0.0"
    return bind, bind


def _doctor_security_gateway_has_auth(gateway: dict[str, object]) -> bool:
    auth = _dict_config(gateway.get("auth"))
    mode = _optional_cli_string(auth.get("mode")) or "token"
    token_configured = _has_configured_secret_input(
        auth.get("token")
    ) or _optional_cli_string(os.environ.get("OPENCLAW_GATEWAY_TOKEN")) is not None
    password_configured = _has_configured_secret_input(
        auth.get("password")
    ) or _optional_cli_string(os.environ.get("OPENCLAW_GATEWAY_PASSWORD")) is not None
    if mode == "password":
        return password_configured
    if mode == "token":
        return token_configured
    return token_configured or password_configured


def _doctor_security_gateway_exposure_warnings(
    snapshot: dict[str, object],
) -> list[str]:
    gateway = _dict_config(snapshot.get("gateway"))
    raw_bind = _optional_cli_string(gateway.get("bind"))
    if raw_bind is not None and raw_bind not in {
        "auto",
        "lan",
        "loopback",
        "custom",
        "tailnet",
    }:
        return []
    bind, resolved_host = _doctor_security_gateway_bind_host(gateway)
    if _doctor_security_is_loopback_host(resolved_host):
        return []
    bind_descriptor = f'"{bind}" ({resolved_host})'
    safer_remote_access = [
        "  Safer remote access: keep bind loopback and use Tailscale Serve/Funnel "
        "or an SSH tunnel.",
        "  Example tunnel: ssh -N -L 18789:127.0.0.1:18789 user@gateway-host",
        "  Docs: https://docs.openclaw.ai/gateway/remote",
    ]
    if not _doctor_security_gateway_has_auth(gateway):
        return [
            "\n".join(
                [
                    f"- CRITICAL: Gateway bound to {bind_descriptor} without authentication.",
                    (
                        "  Anyone on your network (or internet if port-forwarded) can "
                        "fully control your agent."
                    ),
                    "  Fix: openclaw config set gateway.bind loopback",
                    *safer_remote_access,
                    "  Fix: openclaw doctor --fix to generate a token",
                    "  Or set token directly: openclaw config set gateway.auth.mode token",
                ]
            )
        ]
    return [
        "\n".join(
            [
                f"- WARNING: Gateway bound to {bind_descriptor} (network-accessible).",
                "  Ensure your auth credentials are strong and not exposed.",
                *safer_remote_access,
            ]
        )
    ]


