def _model_catalog_ref(entry: dict[str, object]) -> str | None:
    model_id = _optional_cli_string(entry.get("id"))
    if model_id is None:
        return None
    provider = _optional_cli_string(entry.get("provider"))
    if provider is None:
        return model_id
    return f"{provider}/{model_id}"


def _build_capability_model_providers_payload(
    models: list[dict[str, object]],
) -> list[dict[str, object]]:
    grouped: dict[str, dict[str, object]] = {}
    for entry in models:
        provider = _optional_cli_string(entry.get("provider"))
        model_id = _optional_cli_string(entry.get("id"))
        if provider is None or model_id is None:
            continue
        current = grouped.setdefault(
            provider,
            {
                "provider": provider,
                "count": 0,
                "defaults": [],
                "available": True,
                "configured": False,
                "selected": False,
            },
        )
        current_count = current.get("count")
        current["count"] = (current_count if isinstance(current_count, int) else 0) + 1
        defaults = cast("list[str]", current["defaults"])
        if len(defaults) < 3:
            defaults.append(model_id)
    return [grouped[key] for key in sorted(grouped)]


def _optional_model_auth_runtime(services: CliServices) -> Any | None:
    runtime = getattr(services, "model_auth", None)
    if runtime is None:
        runtime = getattr(services, "model_auth_service", None)
    return runtime


def _model_auth_runtime(services: CliServices) -> Any:
    runtime = _optional_model_auth_runtime(services)
    if runtime is None:
        raise ValueError("model auth runtime is unavailable.")
    return runtime


async def _build_capability_model_auth_login_payload(
    services: CliServices,
    *,
    provider: str,
) -> dict[str, object]:
    runtime = _model_auth_runtime(services)
    login = getattr(runtime, "login", None)
    if not callable(login):
        raise ValueError("model auth login is unavailable until model auth runtime is wired.")
    result = await login(provider)
    return dict(result) if isinstance(result, dict) else {"provider": provider}


async def _build_models_auth_login_payload(
    services: CliServices,
    *,
    provider: str | None,
    method: str | None,
    set_default: bool,
) -> dict[str, object]:
    runtime = _model_auth_runtime(services)
    login = getattr(runtime, "login", None)
    if not callable(login):
        raise ValueError("model auth login is unavailable until model auth runtime is wired.")
    try:
        result = await login(provider=provider, method=method, set_default=set_default)
    except TypeError as exc:
        if method is not None or set_default:
            raise ValueError(
                "model auth login runtime does not support --method or --set-default."
            ) from exc
        if provider is None:
            raise ValueError("Missing --provider.") from exc
        result = await login(provider)
    payload = dict(result) if isinstance(result, dict) else {}
    if provider is not None:
        payload.setdefault("provider", provider)
    return payload


async def _build_models_auth_login_github_copilot_payload(
    services: CliServices,
    *,
    yes: bool,
) -> dict[str, object]:
    runtime = _model_auth_runtime(services)
    login = getattr(runtime, "login", None)
    if not callable(login):
        raise ValueError("model auth login is unavailable until model auth runtime is wired.")
    try:
        result = await login(provider="github-copilot", method="device", yes=yes)
    except TypeError as exc:
        raise ValueError(
            "model auth login runtime does not support GitHub Copilot device auth."
        ) from exc
    payload = dict(result) if isinstance(result, dict) else {}
    payload.setdefault("provider", "github-copilot")
    return payload


