async def _build_models_list_payload(
    services: CliServices,
    *,
    provider: str | None,
    local_only: bool,
) -> dict[str, object]:
    payload = await _call_gateway_node_method(services, "models.list", {})
    raw_models = payload.get("models")
    if not isinstance(raw_models, list):
        return {"models": []}
    provider_filter = _optional_cli_string(provider)
    normalized_provider = provider_filter.lower() if provider_filter is not None else None
    models: list[dict[str, object]] = []
    for item in raw_models:
        if not isinstance(item, dict):
            continue
        model = dict(item)
        model_provider = _optional_cli_string(model.get("provider"))
        if normalized_provider is not None:
            if model_provider is None or model_provider.lower() != normalized_provider:
                continue
        if local_only and str(model_provider or "").lower() not in {"local", "ollama", "lmstudio"}:
            continue
        models.append(model)
    return {"models": models}


def _auth_payload_from_gateway_status(
    payload: dict[str, object],
    *,
    providers_in_use: list[str],
    probe: bool,
) -> dict[str, object]:
    raw_providers = payload.get("providers")
    providers = [
        dict(provider)
        for provider in (raw_providers if isinstance(raw_providers, list) else [])
        if isinstance(provider, dict)
    ]
    provider_ids = {
        provider_id
        for provider in providers
        for provider_id in (_optional_cli_string(provider.get("provider")),)
        if provider_id is not None
    }
    missing = [
        provider
        for provider in providers_in_use
        if provider not in provider_ids
        or any(
            _optional_cli_string(entry.get("provider")) == provider
            and (_optional_cli_string(entry.get("status")) or "missing")
            in {"missing", "expired"}
            for entry in providers
        )
    ]
    oauth_profiles: list[dict[str, object]] = []
    oauth_provider_rows: list[dict[str, object]] = []
    providers_with_oauth: list[str] = []
    for provider in providers:
        provider_id = _optional_cli_string(provider.get("provider"))
        if provider_id is None:
            continue
        raw_profiles = provider.get("profiles")
        profiles = [
            dict(profile)
            for profile in (raw_profiles if isinstance(raw_profiles, list) else [])
            if isinstance(profile, dict)
        ]
        oauth_like = [
            profile
            for profile in profiles
            if _optional_cli_string(profile.get("type")) in {"oauth", "token"}
        ]
        if oauth_like:
            providers_with_oauth.append(f"{provider_id} ({len(oauth_like)})")
            oauth_provider_rows.append({"provider": provider_id, "profiles": len(oauth_like)})
        for profile in oauth_like:
            row = dict(profile)
            row.setdefault("provider", provider_id)
            oauth_profiles.append(row)
    provider_statuses = {
        (_optional_cli_string(provider.get("status")) or "missing")
        for provider in providers
    }
    if missing or provider_statuses & {"missing", "expired"}:
        status = "error"
    elif provider_statuses & {"expiring"}:
        status = "expiring"
    elif providers:
        status = "ok"
    else:
        status = "unavailable"
    probes: dict[str, object] | None
    if probe:
        probes = {
            provider_id: {"status": _optional_cli_string(provider.get("status")) or "missing"}
            for provider in providers
            for provider_id in (_optional_cli_string(provider.get("provider")),)
            if provider_id is not None
        }
    else:
        probes = None
    return {
        "status": status,
        "providersWithOAuth": providers_with_oauth,
        "missingProvidersInUse": missing,
        "providers": providers,
        "unusableProfiles": [],
        "oauth": {
            "profiles": oauth_profiles,
            "providers": oauth_provider_rows,
        },
        "probes": probes,
    }


async def _build_models_status_payload(
    services: CliServices,
    *,
    probe: bool,
) -> dict[str, object]:
    catalog = await _build_models_list_payload(
        services,
        provider=None,
        local_only=False,
    )
    raw_models = catalog.get("models")
    models = [item for item in raw_models if isinstance(item, dict)] if isinstance(
        raw_models,
        list,
    ) else []
    default_model = next(
        (item for item in models if item.get("isDefault") is True),
        models[0] if models else None,
    )
    default_label = _model_display_label(default_model) if default_model is not None else None
    resolved_default = _model_reference(default_model) if default_model is not None else None
    allowed = [
        model_ref
        for model_ref in (_model_reference(item) for item in models)
        if model_ref is not None
    ]
    providers_in_use = sorted(
        {
            provider
            for provider in (_optional_cli_string(item.get("provider")) for item in models)
            if provider is not None
        }
    )
    probes: dict[str, object] | None = None
    if probe:
        probes = {
            "status": "unavailable",
            "reason": "models status probes require the model auth health runtime.",
        }
    auth_payload: dict[str, object] = {
        "status": "unavailable",
        "providersWithOAuth": [],
        "missingProvidersInUse": providers_in_use,
        "providers": [],
        "unusableProfiles": [],
        "oauth": {
            "profiles": [],
            "providers": [],
        },
        "probes": probes,
    }
    auth_runtime = _optional_model_auth_runtime(services)
    status = getattr(auth_runtime, "status", None) if auth_runtime is not None else None
    if not callable(status) and auth_runtime is not None:
        status = getattr(auth_runtime, "get_status", None)
    if callable(status):
        runtime_status = await status(providers=providers_in_use, probe=probe)
        if isinstance(runtime_status, dict):
            runtime_auth = runtime_status.get("auth")
            if isinstance(runtime_auth, dict):
                auth_payload.update(dict(runtime_auth))
            else:
                auth_payload.update(dict(runtime_status))
    elif auth_runtime is None and probe:
        try:
            runtime_status = await _call_gateway_node_method(
                services,
                "models.authStatus",
                {"refresh": probe},
            )
        except RuntimeError:
            runtime_status = {}
        if runtime_status:
            auth_payload.update(
                _auth_payload_from_gateway_status(
                    runtime_status,
                    providers_in_use=providers_in_use,
                    probe=probe,
                )
            )
    return {
        "ok": True,
        "defaultModel": default_label,
        "resolvedDefault": resolved_default,
        "fallbacks": _model_fallbacks_from_services_config(services),
        "imageModel": None,
        "imageFallbacks": _model_fallbacks_from_services_config(services, key="imageModel"),
        "aliases": _model_aliases_from_services_config(services),
        "allowed": allowed,
        "auth": auth_payload,
    }


def _model_reference(model: dict[str, object] | None) -> str | None:
    if model is None:
        return None
    model_id = _model_display_label(model)
    if model_id is None:
        return None
    provider = _optional_cli_string(model.get("provider"))
    return f"{provider}/{model_id}" if provider is not None else model_id


def _model_display_label(model: dict[str, object]) -> str | None:
    return _optional_cli_string(model.get("id")) or _optional_cli_string(model.get("name"))


async def _build_plugin_inspect_payload(
    services: CliServices,
    *,
    plugin_id: str | None,
    inspect_all: bool,
    runtime_inspection: bool = False,
) -> dict[str, object] | list[dict[str, object]]:
    def parse_inventory(
        inventory: dict[str, object],
    ) -> tuple[list[dict[str, object]], list[dict[str, object]]]:
        plugins = inventory.get("plugins")
        plugin_rows = [
            plugin for plugin in plugins if isinstance(plugin, dict)
        ] if isinstance(
            plugins,
            list,
        ) else []
        raw_diagnostics = inventory.get("diagnostics")
        diagnostics = [
            diagnostic
            for diagnostic in raw_diagnostics
            if isinstance(diagnostic, dict)
        ] if isinstance(raw_diagnostics, list) else []
        return plugin_rows, diagnostics

    static_inventory = await _build_plugins_inventory_payload(
        services,
        enabled_only=False,
        runtime_inspection=False,
    )
    plugin_rows, diagnostics = parse_inventory(static_inventory)
    runtime_specs = _plugin_runtime_specs_from_services(services)
    if inspect_all:
        if runtime_inspection:
            runtime_inventory = await _build_plugins_inventory_payload(
                services,
                enabled_only=False,
                runtime_inspection=True,
            )
            plugin_rows, diagnostics = parse_inventory(runtime_inventory)
            runtime_specs = _plugin_inspect_runtime_specs_from_rows(
                services,
                plugin_rows,
                workspace_dir=_optional_cli_string(runtime_inventory.get("workspaceDir")),
            )
        return [
            _plugin_inspect_report(
                plugin,
                runtime_specs=runtime_specs,
                policy=_plugin_inspect_policy_from_services(services, plugin),
                diagnostics=diagnostics,
            )
            for plugin in plugin_rows
        ]
    normalized_id = _optional_cli_string(plugin_id)
    if normalized_id is None:
        raise ValueError("Provide a plugin id or use --all.")
    plugin = _find_plugin_record(plugin_rows, normalized_id)
    if plugin is None:
        raise KeyError(normalized_id)
    if runtime_inspection:
        runtime_inventory = await _build_plugins_inventory_payload(
            services,
            enabled_only=False,
            runtime_inspection=True,
            only_plugin_ids=(normalized_id,),
        )
        runtime_plugin_rows, diagnostics = parse_inventory(runtime_inventory)
        plugin = _find_plugin_record(runtime_plugin_rows, normalized_id) or plugin
        runtime_specs = _plugin_inspect_runtime_specs_from_rows(
            services,
            runtime_plugin_rows,
            workspace_dir=_optional_cli_string(runtime_inventory.get("workspaceDir")),
        )
    return _plugin_inspect_report(
        plugin,
        runtime_specs=runtime_specs,
        policy=_plugin_inspect_policy_from_services(services, plugin),
        diagnostics=diagnostics,
    )


def _plugin_inspect_runtime_specs_from_rows(
    services: object,
    plugin_rows: Sequence[Mapping[str, object]],
    *,
    workspace_dir: str | None = None,
) -> tuple[GatewayPluginRuntimeExecutorSpec, ...]:
    config_snapshot = _doctor_config_snapshot(getattr(services, "gateway_config", None))
    return _plugin_runtime_specs_from_services(
        services,
        plugin_rows=[
            plugin for plugin in plugin_rows if _plugin_row_runtime_activated(plugin)
        ],
        config_snapshot=config_snapshot,
        workspace_dir=workspace_dir,
    )


def _find_plugin_record(
    plugins: list[dict[str, object]],
    plugin_id: str,
) -> dict[str, object] | None:
    needle = plugin_id.strip().lower()
    for plugin in plugins:
        candidate_id = str(plugin.get("id") or "").strip().lower()
        candidate_name = str(plugin.get("name") or "").strip().lower()
        if needle in {candidate_id, candidate_name}:
            return plugin
    return None


def _plugin_inspect_report(
    plugin: dict[str, object],
    *,
    runtime_specs: tuple[GatewayPluginRuntimeExecutorSpec, ...] = (),
    policy: dict[str, object] | None = None,
    diagnostics: Sequence[dict[str, object]] = (),
) -> dict[str, object]:
    capabilities = plugin.get("capabilities")
    capability_ids = [
        str(capability)
        for capability in (capabilities if isinstance(capabilities, list) else [])
        if str(capability).strip()
    ]
    install = plugin.get("install")
    runtime_tool_entries = _plugin_runtime_tool_entries(plugin, runtime_specs)
    runtime_tools = _plugin_runtime_tool_names(runtime_tool_entries)
    runtime_dependencies = _plugin_record_runtime_dependencies(plugin)
    inspected_plugin = dict(plugin)
    if runtime_tools:
        inspected_plugin["imported"] = True
    report: dict[str, object] = {
        "plugin": inspected_plugin,
        "shape": _plugin_inspect_shape(plugin),
        "capabilityMode": "runtime" if runtime_tools else "inventory",
        "capabilities": _plugin_inspect_capabilities(
            capability_ids,
            runtime_tools=runtime_tools,
        ),
        "compatibility": _plugin_compatibility_notices(plugin),
        "bundleCapabilities": _plugin_record_string_list(plugin, "bundleCapabilities"),
        "typedHooks": _plugin_record_typed_hooks(plugin),
        "customHooks": _plugin_record_custom_hooks(plugin),
        "tools": runtime_tool_entries,
        "commands": _plugin_record_string_list(plugin, "commands"),
        "cliCommands": _plugin_record_string_list(plugin, "cliCommands"),
        "services": _plugin_record_string_list(plugin, "services"),
        "gatewayMethods": _plugin_record_string_list(plugin, "gatewayMethods"),
        "mcpServers": _plugin_record_string_list(plugin, "mcpServers"),
        "lspServers": _plugin_record_string_list(plugin, "lspServers"),
        "httpRouteCount": _plugin_record_http_route_count(plugin),
        "policy": dict(policy) if policy is not None else {},
        "diagnostics": _plugin_scoped_diagnostics(plugin, diagnostics),
        "install": dict(install) if isinstance(install, dict) else None,
    }
    if runtime_dependencies:
        report["runtimeDependencies"] = runtime_dependencies
    return report


def _plugin_scoped_diagnostics(
    plugin: dict[str, object],
    diagnostics: Sequence[dict[str, object]],
) -> list[dict[str, object]]:
    plugin_id = _optional_cli_string(plugin.get("id"))
    if plugin_id is None:
        return []
    return [
        dict(diagnostic)
        for diagnostic in diagnostics
        if _optional_cli_string(diagnostic.get("pluginId")) == plugin_id
    ]


def _mark_plugin_import_state(
    plugins: list[dict[str, object]],
    runtime_specs: tuple[GatewayPluginRuntimeExecutorSpec, ...],
    *,
    loaded_non_bundle_imported: bool = False,
) -> None:
    for plugin in plugins:
        runtime_tools = _plugin_runtime_tool_names(
            _plugin_runtime_tool_entries(plugin, runtime_specs)
        )
        is_bundle = str(plugin.get("format") or "").strip() == "bundle"
        plugin_status = str(plugin.get("status") or "").strip()
        is_diagnostics_loaded = (
            loaded_non_bundle_imported
            and plugin_status in {"loaded", "error"}
        )
        plugin["imported"] = (
            not is_bundle
            and (
                plugin.get("imported") is True
                or bool(runtime_tools)
                or is_diagnostics_loaded
            )
        )


def _normalize_bundled_plugin_reported_versions(
    plugins: list[dict[str, object]],
    *,
    host_version: str | None,
) -> None:
    host_base = _openclaw_version_base(host_version)
    for plugin in plugins:
        if _optional_cli_string(plugin.get("origin")) != "bundled":
            continue
        raw_version = _optional_cli_string(plugin.get("version"))
        reported = host_base or _openclaw_version_base(raw_version) or raw_version
        if reported is not None:
            plugin["version"] = reported


def _plugin_report_host_version(config_snapshot: Mapping[str, object]) -> str | None:
    return _optional_cli_string(config_snapshot.get("serverVersion")) or __version__


def _openclaw_version_base(value: object) -> str | None:
    text = _optional_cli_string(value)
    if text is None:
        return None
    match = re.match(r"^(\d+)\.(\d+)\.(\d+)(?:[-+].*)?$", text)
    if match is None:
        return None
    return f"{match.group(1)}.{match.group(2)}.{match.group(3)}"


def _plugin_record_string_list(plugin: dict[str, object], key: str) -> list[str]:
    value = plugin.get(key)
    if not isinstance(value, list):
        return []
    return _dedupe_cli_strings(
        [
            text
            for item in value
            if (text := _optional_cli_string(item)) is not None
        ]
    )


def _plugin_record_http_route_count(plugin: dict[str, object]) -> int:
    for key in ("httpRoutes", "httpRouteCount"):
        value = plugin.get(key)
        if isinstance(value, bool):
            continue
        if isinstance(value, int):
            return max(0, value)
        if isinstance(value, list):
            return len(value)
    return 0


def _plugin_record_typed_hooks(plugin: dict[str, object]) -> list[dict[str, object]]:
    raw_hooks = plugin.get("typedHooks")
    hooks: list[dict[str, object]] = []
    for entry in raw_hooks if isinstance(raw_hooks, list) else []:
        if not isinstance(entry, dict):
            continue
        name = _optional_cli_string(entry.get("name"))
        if name is None:
            continue
        hook: dict[str, object] = {"name": name}
        priority = entry.get("priority")
        if priority is not None and not isinstance(priority, bool):
            hook["priority"] = priority
        hooks.append(hook)
    return hooks


def _plugin_record_custom_hooks(plugin: dict[str, object]) -> list[dict[str, object]]:
    raw_hooks = plugin.get("customHooks")
    hooks: list[dict[str, object]] = []
    for entry in raw_hooks if isinstance(raw_hooks, list) else []:
        if not isinstance(entry, dict):
            continue
        name = _optional_cli_string(entry.get("name"))
        if name is None:
            continue
        events = _string_list_or_none(entry.get("events")) or []
        hooks.append({"name": name, "events": events})
    return hooks


def _plugin_runtime_specs_from_services(
    services: object,
    *,
    plugin_rows: Sequence[Mapping[str, object]] = (),
    config_snapshot: Mapping[str, object] | None = None,
    workspace_dir: str | None = None,
    diagnostics: list[dict[str, object]] | None = None,
) -> tuple[GatewayPluginRuntimeExecutorSpec, ...]:
    specs: list[GatewayPluginRuntimeExecutorSpec] = []
    seen_tools: set[str] = set()
    for candidate in (
        getattr(services, "plugin_runtime_service", None),
        getattr(services, "gateway_plugin_runtime", None),
        getattr(services, "plugin_runtime", None),
        getattr(getattr(services, "gateway_node_methods", None), "_plugin_runtime_service", None),
    ):
        catalog_specs = getattr(candidate, "catalog_specs", None)
        if not callable(catalog_specs):
            continue
        raw_specs = catalog_specs(include_owner_only=True)
        if isinstance(raw_specs, tuple | list):
            _extend_plugin_runtime_specs(specs, seen_tools, raw_specs)
            break
    adapter_specs = _plugin_runtime_specs_from_installed_activation_adapter(
        services,
        plugin_rows=plugin_rows,
        config_snapshot=config_snapshot or {},
        existing_tool_names=seen_tools,
        workspace_dir=workspace_dir,
        diagnostics=diagnostics,
    )
    _extend_plugin_runtime_specs(specs, seen_tools, adapter_specs)
    return tuple(specs)


def _extend_plugin_runtime_specs(
    specs: list[GatewayPluginRuntimeExecutorSpec],
    seen_tools: set[str],
    candidates: Iterable[object],
) -> None:
    for candidate in candidates:
        if not isinstance(candidate, GatewayPluginRuntimeExecutorSpec):
            continue
        tool_key = candidate.tool.strip()
        if not tool_key or tool_key in seen_tools:
            continue
        seen_tools.add(tool_key)
        specs.append(candidate)


def _plugin_runtime_specs_from_installed_activation_adapter(
    services: object,
    *,
    plugin_rows: Sequence[Mapping[str, object]],
    config_snapshot: Mapping[str, object],
    existing_tool_names: Iterable[str],
    workspace_dir: str | None,
    diagnostics: list[dict[str, object]] | None,
) -> tuple[GatewayPluginRuntimeExecutorSpec, ...]:
    if not plugin_rows:
        return ()
    adapter = None
    for attr in (
        "installed_plugin_runtime_activation_adapter",
        "plugin_runtime_activation_adapter",
        "installed_plugin_runtime_loader",
        "plugin_runtime_loader",
    ):
        candidate = getattr(services, attr, None)
        if candidate is not None:
            adapter = candidate
            break
    if adapter is None:
        return ()
    only_plugin_ids = _dedupe_cli_strings(
        [
            plugin_id
            for plugin in plugin_rows
            if (plugin_id := _optional_cli_string(plugin.get("id"))) is not None
        ]
    )
    context: dict[str, object] = {
        "plugins": [dict(plugin) for plugin in plugin_rows],
        "rawConfig": dict(config_snapshot),
        "config": dict(config_snapshot),
        "activationSourceConfig": dict(config_snapshot),
        "autoEnabledReasons": {},
        "env": dict(os.environ),
        "onlyPluginIds": only_plugin_ids,
        "throwOnLoadError": True,
    }
    if workspace_dir is not None:
        context["workspaceDir"] = workspace_dir
    try:
        result = _call_plugin_runtime_activation_adapter(adapter, context)
    except Exception as exc:
        _record_plugin_runtime_activation_adapter_error(
            plugin_rows,
            error=exc,
            diagnostics=diagnostics,
        )
        return ()
    if result is None:
        return ()
    if isinstance(result, tuple | list):
        raw_specs = tuple(
            spec
            for spec in result
            if isinstance(spec, GatewayPluginRuntimeExecutorSpec)
        )
    elif isinstance(result, Mapping):
        registry = result.get("registry")
        registry_payload = registry if isinstance(registry, Mapping) else result
        raw_specs = build_plugin_runtime_executor_specs_from_active_registry(
            registry_payload,
            existing_tool_names=existing_tool_names,
            tool_allowlist=("group:plugins",),
        )
    else:
        return ()
    return _filter_plugin_runtime_specs_by_manifest_contracts(
        raw_specs,
        plugin_rows=plugin_rows,
        diagnostics=diagnostics,
    )


def _filter_plugin_runtime_specs_by_manifest_contracts(
    specs: Sequence[GatewayPluginRuntimeExecutorSpec],
    *,
    plugin_rows: Sequence[Mapping[str, object]],
    diagnostics: list[dict[str, object]] | None,
) -> tuple[GatewayPluginRuntimeExecutorSpec, ...]:
    declared_by_plugin: dict[str, tuple[str, ...]] = {}
    source_by_plugin: dict[str, str | None] = {}
    for plugin in plugin_rows:
        plugin_id = _optional_cli_string(plugin.get("id"))
        if plugin_id is None:
            continue
        contracts = plugin.get("contracts")
        contract_payload = contracts if isinstance(contracts, Mapping) else {}
        declared_by_plugin[plugin_id] = tuple(
            _plugin_manifest_string_list(contract_payload.get("tools"))
        )
        source_by_plugin[plugin_id] = _optional_cli_string(plugin.get("source"))
    if not declared_by_plugin:
        return tuple(specs)
    accepted: list[GatewayPluginRuntimeExecutorSpec] = []
    missing_contract_plugins: set[str] = set()
    undeclared_by_plugin: dict[str, list[str]] = {}
    for spec in specs:
        plugin_id = _optional_cli_string(spec.plugin_id)
        if plugin_id is None or plugin_id not in declared_by_plugin:
            accepted.append(spec)
            continue
        declared = declared_by_plugin[plugin_id]
        if not declared:
            missing_contract_plugins.add(plugin_id)
            continue
        declared_keys = {str(tool).strip().lower() for tool in declared}
        tool_key = spec.tool.strip().lower()
        if tool_key not in declared_keys:
            undeclared_by_plugin.setdefault(plugin_id, []).append(spec.tool)
            continue
        accepted.append(spec)
    if diagnostics is not None:
        for plugin_id in declared_by_plugin:
            source = source_by_plugin.get(plugin_id)
            if plugin_id in missing_contract_plugins:
                _record_plugin_runtime_contract_diagnostic(
                    diagnostics,
                    plugin_id=plugin_id,
                    source=source,
                    message=(
                        "plugin must declare contracts.tools before registering "
                        "agent tools"
                    ),
                )
            undeclared = _dedupe_cli_strings(undeclared_by_plugin.get(plugin_id, []))
            if undeclared:
                _record_plugin_runtime_contract_diagnostic(
                    diagnostics,
                    plugin_id=plugin_id,
                    source=source,
                    message=(
                        "plugin must declare contracts.tools for: "
                        f"{', '.join(undeclared)}"
                    ),
                )
    return tuple(accepted)


def _record_plugin_runtime_contract_diagnostic(
    diagnostics: list[dict[str, object]],
    *,
    plugin_id: str,
    source: str | None,
    message: str,
) -> None:
    diagnostic: dict[str, object] = {
        "level": "error",
        "pluginId": plugin_id,
        "message": message,
    }
    if source is not None:
        diagnostic["source"] = source
    diagnostics.append(diagnostic)


def _record_plugin_runtime_activation_adapter_error(
    plugin_rows: Sequence[Mapping[str, object]],
    *,
    error: Exception,
    diagnostics: list[dict[str, object]] | None,
) -> None:
    message = f"failed to load plugin: {error}"
    failed_at = datetime.now(UTC).isoformat(timespec="milliseconds").replace("+00:00", "Z")
    for plugin in plugin_rows:
        plugin_id = _optional_cli_string(plugin.get("id"))
        source = _optional_cli_string(plugin.get("source"))
        if isinstance(plugin, dict):
            plugin["status"] = "error"
            plugin["description"] = message
            plugin["failurePhase"] = "load"
            plugin["failedAt"] = failed_at
        if diagnostics is None:
            continue
        diagnostic: dict[str, object] = {
            "level": "error",
            "message": message,
            "failurePhase": "load",
        }
        if plugin_id is not None:
            diagnostic["pluginId"] = plugin_id
        if source is not None:
            diagnostic["source"] = source
        diagnostics.append(diagnostic)


def _call_plugin_runtime_activation_adapter(
    adapter: object,
    context: Mapping[str, object],
) -> object | None:
    for method_name in ("activate_installed_plugins", "activate", "load"):
        method = getattr(adapter, method_name, None)
        if callable(method):
            return method(dict(context))
    if callable(adapter):
        return adapter(dict(context))
    return None


def _plugin_runtime_tool_entries(
    plugin: dict[str, object],
    runtime_specs: tuple[GatewayPluginRuntimeExecutorSpec, ...],
) -> list[dict[str, object]]:
    plugin_id = _optional_cli_string(plugin.get("id"))
    plugin_name = _optional_cli_string(plugin.get("name"))
    entries: list[tuple[str, bool]] = []
    seen: set[tuple[str, bool]] = set()
    for spec in runtime_specs:
        if not _plugin_runtime_spec_matches_plugin(
            spec,
            plugin_id=plugin_id,
            plugin_name=plugin_name,
        ):
            continue
        tool = _optional_cli_string(spec.tool)
        if tool is None:
            continue
        key = (tool, spec.optional)
        if key in seen:
            continue
        seen.add(key)
        entries.append(key)
    return [
        {"names": [tool], "optional": optional}
        for tool, optional in sorted(entries, key=lambda item: item[0])
    ]


def _plugin_runtime_tool_names(runtime_tool_entries: list[dict[str, object]]) -> list[str]:
    names: list[str] = []
    for entry in runtime_tool_entries:
        raw_names = entry.get("names")
        if not isinstance(raw_names, list):
            continue
        names.extend(
            text
            for item in raw_names
            if (text := _optional_cli_string(item)) is not None
        )
    return sorted(_dedupe_cli_strings(names))


def _plugin_runtime_spec_matches_plugin(
    spec: GatewayPluginRuntimeExecutorSpec,
    *,
    plugin_id: str | None,
    plugin_name: str | None,
) -> bool:
    candidate_ids = {
        value.strip().lower()
        for value in (plugin_id, plugin_name)
        if value is not None and value.strip()
    }
    if not candidate_ids:
        return False
    return any(
        candidate is not None and candidate.strip().lower() in candidate_ids
        for candidate in (spec.plugin_id, spec.plugin_name)
    )


def _plugin_inspect_capabilities(
    capability_ids: list[str],
    *,
    runtime_tools: list[str],
) -> list[dict[str, object]]:
    if runtime_tools:
        return [{"kind": "runtime-tools", "ids": runtime_tools}]
    if capability_ids:
        return [{"kind": "inventory", "ids": capability_ids}]
    return []


def _plugin_inspect_policy_from_services(
    services: object,
    plugin: dict[str, object],
) -> dict[str, object]:
    plugin_id = _optional_cli_string(plugin.get("id"))
    if plugin_id is None:
        return {}
    snapshot = _gateway_config_snapshot_for_cli(services)
    plugins = snapshot.get("plugins")
    if not isinstance(plugins, dict):
        return {}
    entries = plugins.get("entries")
    if not isinstance(entries, dict):
        return {}
    entry = entries.get(plugin_id)
    if not isinstance(entry, dict):
        return {}
    policy: dict[str, object] = {}
    hooks = entry.get("hooks")
    if isinstance(hooks, dict) and isinstance(hooks.get("allowPromptInjection"), bool):
        policy["allowPromptInjection"] = hooks["allowPromptInjection"]
    subagent = entry.get("subagent")
    if isinstance(subagent, dict):
        if isinstance(subagent.get("allowModelOverride"), bool):
            policy["allowModelOverride"] = subagent["allowModelOverride"]
        allowed_models = _string_list_or_none(subagent.get("allowedModels"))
        if allowed_models is not None:
            policy["allowedModels"] = allowed_models
        if isinstance(subagent.get("hasAllowedModelsConfig"), bool):
            policy["hasAllowedModelsConfig"] = subagent["hasAllowedModelsConfig"]
        elif allowed_models is not None:
            policy["hasAllowedModelsConfig"] = True
    return policy


def _plugin_inspect_shape(plugin: dict[str, object]) -> str:
    shape = _optional_cli_string(plugin.get("shape"))
    if shape is not None:
        return shape
    plugin_id = str(plugin.get("id") or "").strip()
    if plugin_id.startswith("hermes_plugin:"):
        return "hermes-inventory"
    if plugin_id.startswith("codex_"):
        return "openzues-runtime-inventory"
    return "openzues-inventory"


def _plugin_compatibility_notices(plugin: dict[str, object]) -> list[dict[str, object]]:
    plugin_id = str(plugin.get("id") or "").strip()
    if not plugin_id:
        return []
    notices: list[dict[str, object]] = []
    if plugin.get("usesLegacyBeforeAgentStart") is True:
        notices.append(
            {
                "pluginId": plugin_id,
                "code": "legacy-before-agent-start",
                "severity": "warn",
                "message": (
                    "still uses legacy before_agent_start; keep regression coverage "
                    "on this plugin, and prefer before_model_resolve/before_prompt_build "
                    "for new work."
                ),
            }
        )
    if _plugin_inspect_shape(plugin) == "hook-only":
        notices.append(
            {
                "pluginId": plugin_id,
                "code": "hook-only",
                "severity": "info",
                "message": (
                    "is hook-only. This remains a supported compatibility path, but it "
                    "has not migrated to explicit capability registration yet."
                ),
            }
        )
    return notices


def _plugin_failure_phase(value: object) -> str | None:
    phase = _optional_cli_string(value)
    return phase if phase in {"validation", "load", "register"} else None


def _plugin_failed_at(value: object) -> str | None:
    if isinstance(value, datetime):
        return value.isoformat()
    return _optional_cli_string(value)


def _format_plugin_compatibility_notice(notice: dict[str, object]) -> str:
    plugin_id = str(notice.get("pluginId") or "").strip()
    message = str(notice.get("message") or "").strip()
    return f"{plugin_id} {message}".strip()


def _plugin_record_from_deck_item(
    item: dict[str, object],
    *,
    workspace_dir: str | None,
) -> dict[str, object] | None:
    plugin_id = _optional_cli_string(item.get("key"))
    if plugin_id is None:
        return None
    name = _optional_cli_string(item.get("label")) or plugin_id
    parity_status = _optional_cli_string(item.get("status")) or "advisory"
    capabilities = item.get("capabilities")
    capability_list = [
        str(capability)
        for capability in (capabilities if isinstance(capabilities, list) else [])
        if str(capability).strip()
    ]
    record: dict[str, object] = {
        "id": plugin_id,
        "name": name,
        "status": _openclaw_plugin_status(parity_status),
        "format": "openzues",
        "source": "openzues",
        "origin": "runtime",
        "description": str(item.get("summary") or "").strip(),
        "capabilities": capability_list,
        "parityStatus": parity_status,
    }
    if plugin_id.startswith("codex_"):
        record["source"] = "live_codex"
        record["origin"] = "runtime"
    elif plugin_id.startswith("hermes_plugin:"):
        plugin_name = plugin_id.partition(":")[2].strip()
        record["format"] = "hermes"
        record["origin"] = "hermes_source"
        record["source"] = (
            str(Path(workspace_dir) / "plugins" / plugin_name)
            if workspace_dir is not None and plugin_name
            else "hermes_source"
        )
    origin = _optional_cli_string(item.get("origin"))
    if origin is not None:
        record["origin"] = origin
    version = _optional_cli_string(item.get("version"))
    if version is not None:
        record["version"] = version
    shape = _optional_cli_string(item.get("shape"))
    if shape is not None:
        record["shape"] = shape
    if item.get("usesLegacyBeforeAgentStart") is True:
        record["usesLegacyBeforeAgentStart"] = True
    if item.get("imported") is True:
        record["imported"] = True
    failure_phase = _plugin_failure_phase(item.get("failurePhase"))
    if failure_phase is not None:
        record["failurePhase"] = failure_phase
    failed_at = _plugin_failed_at(item.get("failedAt"))
    if failed_at is not None:
        record["failedAt"] = failed_at
    error = _optional_cli_string(item.get("error"))
    if error is not None:
        record["error"] = error
    item_root_dir = _optional_cli_string(item.get("rootDir"))
    for metadata_key, metadata_value in _plugin_manifest_root_metadata(
        item,
        root_dir=Path(item_root_dir) if item_root_dir is not None else None,
    ).items():
        record[metadata_key] = metadata_value
    for key in (
        "commands",
        "cliCommands",
        "services",
        "gatewayMethods",
        "bundleCapabilities",
    ):
        values = _plugin_record_string_list(item, key)
        if values:
            record[key] = values
    typed_hooks = _plugin_record_typed_hooks(item)
    if typed_hooks:
        record["typedHooks"] = typed_hooks
    custom_hooks = _plugin_record_custom_hooks(item)
    if custom_hooks:
        record["customHooks"] = custom_hooks
    command_aliases = _plugin_manifest_command_aliases(item.get("commandAliases"))
    if command_aliases:
        record["commandAliases"] = command_aliases
    activation = _plugin_manifest_activation(item.get("activation"))
    if activation:
        record["activation"] = activation
    setup = _plugin_manifest_setup(item.get("setup"))
    if setup:
        record["setup"] = setup
    qa_runners = _plugin_manifest_qa_runners(item.get("qaRunners"))
    if qa_runners:
        record["qaRunners"] = qa_runners
    channel_configs = _plugin_manifest_channel_configs(item.get("channelConfigs"))
    if channel_configs:
        record["channelConfigs"] = channel_configs
    model_support = _plugin_manifest_model_support(item.get("modelSupport"))
    if model_support:
        record["modelSupport"] = model_support
    config_contracts = _plugin_manifest_config_contracts(item.get("configContracts"))
    if config_contracts:
        record["configContracts"] = config_contracts
    for metadata_key, metadata_value in _plugin_manifest_auth_env_metadata(item).items():
        record[metadata_key] = metadata_value
    route_count = _plugin_record_http_route_count(item)
    if route_count:
        record["httpRoutes"] = route_count
    return record


