@plugins_app.command("install")
def plugins_install_command(
    plugin_id: str = typer.Argument(..., help="Plugin id or marketplace plugin name."),
    marketplace: str | None = typer.Option(
        None,
        "--marketplace",
        help="Install from a local Claude-compatible marketplace path or manifest.",
    ),
    force: bool = typer.Option(
        False,
        "--force",
        help="Update an existing native marketplace install record.",
    ),
    link: bool = typer.Option(
        False,
        "--link",
        "-l",
        help="Accepted for OpenClaw CLI compatibility; not supported for marketplace installs.",
    ),
    pin: bool = typer.Option(
        False,
        "--pin",
        help="Accepted for OpenClaw CLI compatibility; not supported for marketplace installs.",
    ),
    dangerously_force_unsafe_install: bool = typer.Option(
        False,
        "--dangerously-force-unsafe-install",
        help="Accepted for OpenClaw CLI compatibility; local marketplace install is metadata-only.",
    ),
    json_output: bool = typer.Option(False, "--json", help="Emit install result as JSON."),
) -> None:
    del dangerously_force_unsafe_install
    resolved_plugin_id = plugin_id
    resolved_marketplace = marketplace
    if resolved_marketplace is None:
        shortcut = _resolve_cli_marketplace_install_shortcut(plugin_id)
        if shortcut is not None:
            resolved_plugin_id, resolved_marketplace = shortcut
    if resolved_marketplace is None:
        local_path = Path(plugin_id).expanduser()
        if local_path.exists():
            if link and force:
                typer.echo("`--force` is not supported with `--link`.", err=True)
                raise typer.Exit(code=1)

            async def _path_action(services: CliServices) -> dict[str, object]:
                return await _build_plugins_path_install_payload(
                    services,
                    plugin_path=plugin_id,
                    link=link,
                    force=force,
                )

            try:
                payload = _run(_run_with_services(_path_action))
            except ValueError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            except RuntimeError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            _emit_plugins_install(payload, json_output=json_output)
            return
        if link:
            typer.echo("`--link` requires a local path.", err=True)
            raise typer.Exit(code=1)
        if _looks_like_cli_local_plugin_install_spec(plugin_id):
            missing_path = Path(plugin_id).expanduser()
            try:
                resolved_missing_path = missing_path.resolve(strict=False)
            except OSError:
                resolved_missing_path = missing_path
            typer.echo(f"Path not found: {resolved_missing_path}", err=True)
            raise typer.Exit(code=1)
        bundled_source = _resolve_cli_bundled_install_plan_before_npm(plugin_id)
        if bundled_source is not None:

            async def _bundled_action(services: CliServices) -> dict[str, object]:
                return await _build_plugins_bundled_install_payload(
                    services,
                    raw_spec=plugin_id,
                    source=bundled_source,
                    force=force,
                )

            try:
                payload = _run(_run_with_services(_bundled_action))
            except ValueError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            except RuntimeError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            _emit_plugins_install(payload, json_output=json_output)
            return
        if _parse_cli_clawhub_plugin_spec(plugin_id) is not None:

            async def _clawhub_action(services: CliServices) -> dict[str, object]:
                return await _build_plugins_clawhub_install_payload(
                    services,
                    raw_spec=plugin_id,
                    force=force,
                )

            try:
                payload = _run(_run_with_services(_clawhub_action))
            except ValueError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            except RuntimeError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            _emit_plugins_install(payload, json_output=json_output)
            return
        preferred_clawhub_spec = _build_cli_preferred_clawhub_spec(plugin_id)
        if preferred_clawhub_spec is not None:

            async def _preferred_clawhub_action(services: CliServices) -> dict[str, object]:
                return await _build_plugins_clawhub_install_payload(
                    services,
                    raw_spec=preferred_clawhub_spec,
                    force=force,
                )

            try:
                payload = _run(_run_with_services(_preferred_clawhub_action))
            except _CliClawHubInstallError as exc:
                if not _should_cli_preferred_clawhub_fallback(exc.code):
                    typer.echo(str(exc), err=True)
                    raise typer.Exit(code=1) from exc
            except ValueError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            except RuntimeError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            else:
                _emit_plugins_install(payload, json_output=json_output)
                return
        if _parse_cli_registry_npm_spec(plugin_id) is not None:

            async def _npm_action(services: CliServices) -> dict[str, object]:
                return await _build_plugins_npm_install_payload(
                    services,
                    raw_spec=plugin_id,
                    force=force,
                    pin=pin,
                )

            try:
                payload = _run(_run_with_services(_npm_action))
            except _CliNpmInstallError as exc:
                bundled_fallback = _resolve_cli_bundled_install_plan_for_npm_failure(
                    raw_spec=plugin_id,
                    code=exc.code,
                )
                if bundled_fallback is None:
                    async def _hook_fallback_action(
                        services: CliServices,
                    ) -> dict[str, object]:
                        return await _build_hooks_npm_install_payload(
                            services,
                            raw_spec=plugin_id,
                            force=force,
                        )

                    try:
                        payload = _run(_run_with_services(_hook_fallback_action))
                    except ValueError as hook_exc:
                        typer.echo(f"{exc}\nAlso not a valid hook pack: {hook_exc}", err=True)
                        raise typer.Exit(code=1) from hook_exc
                    except RuntimeError as hook_exc:
                        typer.echo(f"{exc}\nAlso not a valid hook pack: {hook_exc}", err=True)
                        raise typer.Exit(code=1) from hook_exc
                    _emit_plugins_install(payload, json_output=json_output)
                    return

                async def _bundled_fallback_action(
                    services: CliServices,
                ) -> dict[str, object]:
                    return await _build_plugins_bundled_install_payload(
                        services,
                        raw_spec=plugin_id,
                        source=bundled_fallback,
                        force=force,
                        warning=(
                            f"npm package unavailable for {plugin_id}; "
                            f"using bundled plugin at {bundled_fallback.local_path}."
                        ),
                    )

                try:
                    payload = _run(_run_with_services(_bundled_fallback_action))
                except ValueError as fallback_exc:
                    typer.echo(str(fallback_exc), err=True)
                    raise typer.Exit(code=1) from fallback_exc
                except RuntimeError as fallback_exc:
                    typer.echo(str(fallback_exc), err=True)
                    raise typer.Exit(code=1) from fallback_exc
            except ValueError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            except RuntimeError as exc:
                typer.echo(str(exc), err=True)
                raise typer.Exit(code=1) from exc
            _emit_plugins_install(payload, json_output=json_output)
            return
        typer.echo(
            "Native plugin install currently supports local marketplace installs via "
            "--marketplace.",
            err=True,
        )
        raise typer.Exit(code=1)
    if link:
        typer.echo("`--link` is not supported with `--marketplace`.", err=True)
        raise typer.Exit(code=1)
    if pin:
        typer.echo("`--pin` is not supported with `--marketplace`.", err=True)
        raise typer.Exit(code=1)

    async def _action(services: CliServices) -> dict[str, object]:
        return await _build_plugins_marketplace_install_payload(
            services,
            plugin_id=resolved_plugin_id,
            marketplace=resolved_marketplace,
            force=force,
        )

    try:
        payload = _run(_run_with_services(_action))
    except ValueError as exc:
        typer.echo(str(exc), err=True)
        raise typer.Exit(code=1) from exc
    except RuntimeError as exc:
        typer.echo(str(exc), err=True)
        raise typer.Exit(code=1) from exc
    _emit_plugins_install(payload, json_output=json_output)


@plugins_app.command("uninstall")
def plugins_uninstall_command(
    plugin_id: str = typer.Argument(..., help="Plugin id."),
    keep_files: bool = typer.Option(
        False,
        "--keep-files",
        help="Accepted for OpenClaw CLI compatibility; native local installs keep files.",
    ),
    keep_config: bool = typer.Option(
        False,
        "--keep-config",
        help="Deprecated OpenClaw alias for --keep-files.",
    ),
    force: bool = typer.Option(False, "--force", help="Skip confirmation prompt."),
    dry_run: bool = typer.Option(
        False,
        "--dry-run",
        help="Show what would be removed without writing config.",
    ),
    json_output: bool = typer.Option(False, "--json", help="Emit uninstall result as JSON."),
) -> None:
    del keep_files
    if keep_config and not json_output:
        typer.echo("`--keep-config` is deprecated, use `--keep-files`.")
    if not dry_run and not force:
        if not typer.confirm(f'Uninstall plugin "{plugin_id}"?'):
            typer.echo("Cancelled.")
            return

    async def _action(services: CliServices) -> dict[str, object]:
        return await _build_plugins_uninstall_payload(
            services,
            plugin_id=plugin_id,
            dry_run=dry_run,
        )

    try:
        payload = _run(_run_with_services(_action))
    except ValueError as exc:
        typer.echo(str(exc), err=True)
        raise typer.Exit(code=1) from exc
    except RuntimeError as exc:
        typer.echo(str(exc), err=True)
        raise typer.Exit(code=1) from exc
    _emit_plugins_uninstall(payload, json_output=json_output)


