@app.command("queue")
def queue_command(
    signal_id: str | None = typer.Option(
        None,
        "--signal-id",
        help="Target one radar signal id instead of the next automatic queue move.",
    ),
    plan_only: bool = typer.Option(
        False,
        "--plan",
        help="Preview the next autonomous attention-queue move without executing it.",
    ),
    json_output: bool = typer.Option(
        False,
        "--json",
        help="Emit the queue result as JSON.",
    ),
) -> None:
    async def _action(services: CliServices) -> dict[str, object]:
        dashboard = await _build_operator_dashboard(services)
        typed_dashboard = cast(DashboardView, dashboard)
        plan = plan_attention_queue(typed_dashboard, target_signal_id=signal_id)
        if plan_only:
            if plan is None:
                return {
                    "mode": "plan",
                    "executed": False,
                    "action_kind": "idle",
                    "status": "observed",
                    "reply": _attention_queue_idle_reply(signal_id=signal_id),
                    "signal_id": signal_id,
                    "mission_id": None,
                    "opportunity_id": None,
                    "target_label": None,
                    "mission_payload": None,
                }
            return {
                "mode": "plan",
                "executed": False,
                "action_kind": plan.action_kind,
                "status": plan.status,
                "reply": plan.reply,
                "signal_id": plan.signal_id,
                "mission_id": plan.mission_id,
                "opportunity_id": plan.opportunity_id,
                "target_label": plan.target_label,
                "mission_payload": (
                    plan.mission_payload.model_dump(mode="json")
                    if plan.mission_payload is not None
                    else None
                ),
            }

        if plan is None:
            return {
                "mode": "executed",
                "executed": False,
                "action_kind": "idle",
                "status": "observed",
                "reply": _attention_queue_idle_reply(signal_id=signal_id),
                "signal_id": signal_id,
                "mission_id": None,
                "opportunity_id": None,
                "target_label": None,
            }

        latest_before = await services.database.get_latest_attention_queue_action(
            plan.signal_fingerprint
        )
        executed = await services.control_chat.tick_attention_queue(
            typed_dashboard,
            target_signal_id=signal_id,
        )
        latest_after = await services.database.get_latest_attention_queue_action(
            plan.signal_fingerprint
        )
        if executed and latest_after is not None:
            return {
                "mode": "executed",
                "executed": True,
                "action_kind": latest_after.get("action_kind") or plan.action_kind,
                "status": latest_after.get("status") or plan.status,
                "reply": latest_after.get("summary") or plan.reply,
                "signal_id": latest_after.get("signal_id") or plan.signal_id,
                "mission_id": latest_after.get("mission_id"),
                "opportunity_id": latest_after.get("opportunity_id"),
                "target_label": latest_after.get("target_label") or plan.target_label,
            }
        if latest_before is not None:
            target_label = str(latest_before.get("target_label") or plan.target_label or "").strip()
            target_note = f" `{target_label}`" if target_label else ""
            return {
                "mode": "executed",
                "executed": False,
                "action_kind": latest_before.get("action_kind") or plan.action_kind,
                "status": latest_before.get("status") or "observed",
                "reply": (
                    f"The attention queue already handled{target_note} for this signal, so I "
                    "left it alone."
                ),
                "signal_id": latest_before.get("signal_id") or plan.signal_id,
                "mission_id": latest_before.get("mission_id"),
                "opportunity_id": latest_before.get("opportunity_id"),
                "target_label": latest_before.get("target_label") or plan.target_label,
            }
        return {
            "mode": "executed",
            "executed": False,
            "action_kind": plan.action_kind,
            "status": "observed",
            "reply": "The attention queue did not find a safe move to execute right now.",
            "signal_id": plan.signal_id,
            "mission_id": plan.mission_id,
            "opportunity_id": plan.opportunity_id,
            "target_label": plan.target_label,
        }

    try:
        payload = _run(_run_with_services(_action))
    except ValueError as exc:
        typer.echo(str(exc), err=True)
        raise typer.Exit(code=1) from exc
    _emit_attention_queue_action(payload, json_output=json_output)


@app.command("doctor")
def doctor(
    json_output: bool = typer.Option(
        False,
        "--json",
        help="Emit the Hermes parity doctor view as JSON.",
    ),
    fix: bool = typer.Option(
        False,
        "--fix",
        "--repair",
        help="Run repair-mode doctor checks where native adapters are available.",
    ),
) -> None:
    async def _action(services: CliServices) -> dict[str, object]:
        view = await _try_live_hermes_doctor_view(services.settings)
        if view is None:
            view = await services.hermes_platform.get_doctor_view()
        payload = _with_doctor_legacy_config_payload(
            view.model_dump(mode="json"),
            services.gateway_config,
            should_repair=fix,
        )
        payload = _with_doctor_bundled_plugin_load_paths_payload(
            payload,
            services.gateway_config,
            should_repair=fix,
        )
        payload = _with_doctor_legacy_plugin_manifests_payload(
            payload,
            services.gateway_config,
            should_repair=fix,
        )
        payload = _with_doctor_stale_plugin_config_payload(
            payload,
            services.gateway_config,
            should_repair=fix,
        )
        payload = _with_doctor_open_policy_allow_from_payload(
            payload,
            services.gateway_config,
            should_repair=fix,
        )
        payload = _with_doctor_allowlist_policy_allow_from_payload(
            payload,
            services.gateway_config,
            should_repair=fix,
        )
        payload = _with_doctor_sandbox_warnings(
            payload,
            services.gateway_config,
        )
        payload = _with_doctor_gateway_config_payload(
            payload,
            services.gateway_config,
        )
        payload = _with_doctor_gateway_runtime_payload(
            payload,
            services.gateway_config,
        )
        payload = _with_doctor_claude_cli_payload(
            payload,
            services.gateway_config,
        )
        payload = _with_doctor_gateway_auth_payload(
            payload,
            services.gateway_config,
        )
        payload = await _with_doctor_browser_payload(
            payload,
            services.gateway_config,
            getattr(services, "browser_doctor", None),
        )
        payload = _with_doctor_oauth_tls_payload(
            payload,
            services.gateway_config,
        )
        payload = _with_doctor_hooks_model_payload(
            payload,
            services.gateway_config,
        )
        payload = _with_doctor_bootstrap_size_payload(
            payload,
            services.gateway_config,
        )
        task_flows = await _list_openclaw_task_flows(services)
        payload = _with_doctor_workspace_status_payload(
            payload,
            services.gateway_config,
            task_flows=task_flows,
            runtime_specs=_plugin_runtime_specs_from_services(services),
        )
        data_dir = getattr(services.settings, "data_dir", None)
        payload = _with_doctor_provider_override_warnings(
            payload,
            services.gateway_config,
            data_dir if isinstance(data_dir, Path) else None,
        )
        payload = _with_doctor_sandbox_payload(payload, services.gateway_config)
        if isinstance(data_dir, Path):
            payload = _with_doctor_state_directory_health(payload, data_dir)
            payload = _with_doctor_session_lock_health(
                payload,
                data_dir,
                should_repair=fix,
            )
        payload = _with_doctor_legacy_cron_payload(
            payload,
            services.gateway_config,
            should_repair=fix,
        )
        payload = _with_doctor_security_payload(
            payload,
            services.gateway_config,
            data_dir if isinstance(data_dir, Path) else None,
            should_repair=fix,
        )
        payload = await _with_doctor_channel_doctor_payload(
            payload,
            services.gateway_config,
            getattr(services, "channel_doctor_adapters", None),
            should_repair=fix,
        )
        payload = _with_doctor_shell_completion_payload(
            payload,
            data_dir if isinstance(data_dir, Path) else None,
            should_repair=fix,
        )
        payload = await _with_doctor_gateway_health_payload(
            payload,
            services.settings,
            getattr(services, "gateway_node_methods", None),
        )
        payload = await _with_doctor_memory_search_payload(
            payload,
            getattr(services, "gateway_node_methods", None),
        )
        payload = await _with_doctor_device_pairing_payload(
            payload,
            getattr(services, "gateway_node_methods", None),
            data_dir if isinstance(data_dir, Path) else None,
        )
        payload = await _with_doctor_startup_channel_maintenance_payload(
            payload,
            services.gateway_config,
            getattr(services, "channel_startup_maintenance", None),
            should_repair=fix,
        )
        payload = _with_doctor_bundled_plugin_runtime_dependencies(
            payload,
            services.gateway_config,
        )
        payload = await _with_doctor_runtime_bridge_payload(payload, services)
        payload = _with_doctor_contribution_surfaces(payload)
        return payload

    payload = _run(_run_with_services(_action))
    _emit_hermes_doctor(payload, json_output=json_output)


